     1→import { performance } from 'perf_hooks';
     2→
     3→import { Logger } from '@nestjs/common';
     4→import * as Rollbar from 'rollbar';
     5→
     6→import { rollbar } from '@config/rollbar.config';
     7→
     8→import { EXECUTION_TIME_THRESHOLD_MS } from '@constants/env-variables.constant';
     9→
    10→export interface LogExecutionOptions<TParams, TResponse> {
    11→	logParams?: boolean;
    12→	logResponse?: boolean;
    13→	logExecutionTime?: boolean;
    14→	logErrToRollbar?: boolean;
    15→	rollbarLevel?: 'debug' | 'info' | 'warning' | 'error';
    16→	maskSensitiveData?: boolean;
    17→	sensitiveKeys?: string[];
    18→	customContext?: Record<string, unknown>;
    19→	paramFormatter?: (params: TParams) => unknown;
    20→	responseFormatter?: (response: TResponse) => unknown;
    21→}
    22→
    23→const DEFAULT_OPTIONS: LogExecutionOptions<unknown, unknown> = {
    24→	logParams: true,
    25→	logResponse: true,
    26→	logExecutionTime: true,
    27→	logErrToRollbar: true,
    28→	rollbarLevel: 'debug',
    29→	maskSensitiveData: true,
    30→	sensitiveKeys: [
    31→		'password',
    32→		'pass',
    33→		'token',
    34→		'secret',
    35→		'auth',
    36→		'authorization',
    37→		'cookie',
    38→		'session',
    39→		'credentials',
    40→		'apiKey',
    41→		'_cookie',
    42→		'csrf',
    43→		'_csrf',
    44→	],
    45→	paramFormatter: <TParams>(params: TParams) => params,
    46→	responseFormatter: <TResponse>(response: TResponse) => response,
    47→};
    48→
    49→const thresholdMs = Number(process.env[EXECUTION_TIME_THRESHOLD_MS]);
    50→
    51→export function LogExecution<TParams, TResponse>(
    52→	options: LogExecutionOptions<TParams, TResponse> = {},
    53→): MethodDecorator {
    54→	const config: LogExecutionOptions<TParams, TResponse> = {
    55→		...DEFAULT_OPTIONS,
    56→		...options,
    57→	};
    58→
    59→	return function (
    60→		target: unknown,
    61→		propertyKey: string | symbol,
    62→		descriptor: PropertyDescriptor,
    63→	) {
    64→		const originalMethod = descriptor.value as (...args: unknown[]) => unknown;
    65→		const className = (target as { constructor: { name: string } }).constructor.name;
    66→		const methodName = String(propertyKey);
    67→		const logger = new Logger(`${className}.${methodName}`);
    68→
    69→		descriptor.value = async function (...args: unknown[]) {
    70→			const startTime = performance.now();
    71→
    72→			try {
    73→				const logContext = {
    74→					className,
    75→					methodName,
    76→					timestamp: new Date().toISOString(),
    77→					...(config.customContext ?? {}),
    78→				};
    79→
    80→				let paramsToLog: unknown = config.paramFormatter
    81→					? config.paramFormatter(args as TParams)
    82→					: args;
    83→				if (config.maskSensitiveData) {
    84→					paramsToLog = maskSensitiveData(paramsToLog, config.sensitiveKeys);
    85→				}
    86→
    87→				if (config.logParams) {
    88→					logger.log(
    89→						`[LogExecution]: Method invoked with parameters, ${JSON.stringify({
    90→							params: paramsToLog,
    91→							...logContext,
    92→						})}`,
    93→					);
    94→				}
    95→
    96→				const result = await originalMethod.apply(this, args);
    97→				const endTime = performance.now();
    98→				const executionTime = endTime - startTime;
    99→
   100→				let responseToLog: unknown = config.responseFormatter
   101→					? config.responseFormatter(result as TResponse)
   102→					: result;
   103→				if (config.maskSensitiveData) {
   104→					responseToLog = maskSensitiveData(responseToLog, config.sensitiveKeys);
   105→				}
   106→
   107→				const successLogContext = {
   108→					...logContext,
   109→					executionTimeMs: executionTime,
   110→					response: config.logResponse ? responseToLog : undefined,
   111→				};
   112→
   113→				if (config.logExecutionTime) {
   114→					logger.log(
   115→						`[LogExecution]:Method completed in ${executionTime.toFixed(2)}ms. Result: ${JSON.stringify(successLogContext)}`,
   116→					);
   117→				}
   118→
   119→				if (executionTime > thresholdMs) {
   120→					logger.warn(
   121→						`[LogExecution]: Long execution ${executionTime.toFixed(
   122→							2,
   123→						)}ms, logContext: ${JSON.stringify({ ...successLogContext, success: true })}`,
   124→					);
   125→
   126→					if (config.logErrToRollbar) {
   127→						try {
   128→							const rollbar = getRollbarInstance();
   129→							if (rollbar) {
   130→								rollbar.warning(
   131→									`[LogExecution]: Long execution ${executionTime.toFixed(2)}ms.`,
   132→									{ ...successLogContext, success: true },
   133→								);
   134→							}
   135→						} catch {}
   136→					}
   137→				}
   138→
   139→				return result;
   140→			} catch (error) {
   141→				const endTime = performance.now();
   142→				const executionTime = endTime - startTime;
   143→				const errorLogContext = {
   144→					className,
   145→					methodName,
   146→					timestamp: new Date().toISOString(),
   147→					executionTimeMs: executionTime,
   148→					error: {
   149→						message: (error as Error).message,
   150→						stack: (error as Error).stack,
   151→						name: (error as Error).name,
   152→					},
   153→					...(config.customContext ?? {}),
   154→				};
   155→
   156→				logger.error(
   157→					`[LogExecution]: Method failed after ${executionTime.toFixed(2)}ms: ${
   158→						(error as Error).message
   159→					}, errorLogContext: ${JSON.stringify(errorLogContext)}`,
   160→				);
   161→
   162→				if (config.logErrToRollbar) {
   163→					try {
   164→						const rollbar = getRollbarInstance();
   165→						if (rollbar) {
   166→							rollbar.error(`Method ${className}.${methodName} failed.`, error as Error, {
   167→								...errorLogContext,
   168→								success: false,
   169→							});
   170→						}
   171→					} catch {}
   172→				}
