    19→	private static readonly MOMENTUM_WEIGHT = 0.6;
    20→	private static readonly SIGNIFICANCE_WEIGHT = 0.4;
    21→
    22→	static calculateTrendingScore(data: TrendingScoreData): TrendingScoreResult {
