    29→		const historicalStats = this.calculateStatistics(historicalOrders);
    30→		const forecastStats = this.calculateStatistics(forecastedOrders);
    31→
    32→		const tTestResult = this.performTTest(historicalStats, forecastStats);
    33→		const effectSize = this.calculateEffectSize(historicalStats, forecastStats);
    34→		const momentum = this.calculateMomentum(trendComponent);
    35→		const volatility = this.calculateVolatility(historicalOrders);
    36→
    37→		const isSignificant =
    38→			tTestResult.pValue < this.SIGNIFICANCE_THRESHOLD &&
    39→			Math.abs(effectSize) > this.MIN_EFFECT_SIZE;
    40→
    41→		let trendScore = 0;
    42→		if (isSignificant && effectSize > 0) {
    43→			const momentumFactor = Math.max(0, momentum * 20);
    44→			const significanceFactor = Math.max(0, effectSize * 30);
    45→
    46→			trendScore =
    47→				momentumFactor * this.MOMENTUM_WEIGHT +
    48→				significanceFactor * this.SIGNIFICANCE_WEIGHT;
