    94→		if (pooledVariance <= 0) {
    95→			return { tStatistic: 0, pValue: 1.0 };
    96→		}
    97→
    98→		const standardError = Math.sqrt(pooledVariance * (1 / group1.n + 1 / group2.n));
    99→		const tStatistic = (group2.mean - group1.mean) / standardError;
   100→		const degreesOfFreedom = group1.n + group2.n - 2;
   101→
   102→		const pValue = this.calculatePValue(Math.abs(tStatistic), degreesOfFreedom);
   103→
   104→		return { tStatistic, pValue };
   105→	}
   106→
   107→	private static calculatePValue(tStatistic: number, degreesOfFreedom: number): number {
   108→		if (degreesOfFreedom <= 0) return 1.0;
   109→		if (tStatistic === 0) return 1.0;
   110→
   111→		const betaDistributionInput =
   112→			degreesOfFreedom / (degreesOfFreedom + tStatistic * tStatistic);
   113→
   114→		if (
   115→			betaDistributionInput < 0 ||
   116→			betaDistributionInput > 1 ||
   117→			!Number.isFinite(betaDistributionInput)
   118→		)
   119→			return 1.0;
   120→
   121→		const betaValue = this.incompleteBeta(
   122→			betaDistributionInput,
   123→			degreesOfFreedom / 2,
   124→			0.5,
   125→		);
   126→
   127→		return Math.max(0, Math.min(1, betaValue));
   128→	}
   129→
   130→	private static incompleteBeta(
   131→		inputX: number,
   132→		alphaParameter: number,
   133→		betaParameter: number,
   134→	): number {
   135→		if (inputX <= 0) return 0;
   136→		if (inputX >= 1) return 1;
   137→
   138→		const betaFunction = Math.exp(
   139→			this.gammaLn(alphaParameter + betaParameter) -
   140→				this.gammaLn(alphaParameter) -
   141→				this.gammaLn(betaParameter) +
   142→				alphaParameter * Math.log(inputX) +
   143→				betaParameter * Math.log(1 - inputX),
   144→		);
   145→
   146→		if (inputX < (alphaParameter + 1) / (alphaParameter + betaParameter + 2)) {
   147→			return (
   148→				(betaFunction *
   149→					this.betaContinuedFraction(inputX, alphaParameter, betaParameter)) /
   150→				alphaParameter
   151→			);
   152→		} else {
   153→			return (
   154→				1 -
   155→				(betaFunction *
   156→					this.betaContinuedFraction(1 - inputX, betaParameter, alphaParameter)) /
   157→					betaParameter
   158→			);
   159→		}
   160→	}
   161→
   162→	private static betaContinuedFraction(
   163→		inputX: number,
   164→		alphaParameter: number,
   165→		betaParameter: number,
   166→	): number {
   167→		const maxIterations = 100;
   168→		const epsilon = 3e-7;
   169→
   170→		const sumAlphaBeta = alphaParameter + betaParameter;
   171→		const alphaPlusOne = alphaParameter + 1;
   172→		const alphaMinusOne = alphaParameter - 1;
   173→		let numeratorC = 1;
   174→		let denominatorD = 1 - (sumAlphaBeta * inputX) / alphaPlusOne;
   175→
   176→		if (Math.abs(denominatorD) < epsilon) {
   177→			denominatorD = epsilon;
   178→		}
   179→
   180→		denominatorD = 1 / denominatorD;
   181→		let resultH = denominatorD;
   182→
   183→		for (let iteration = 1; iteration <= maxIterations; iteration++) {
   184→			const doubleIteration = 2 * iteration;
   185→			const firstTerm =
   186→				(iteration * (betaParameter - iteration) * inputX) /
   187→				((alphaMinusOne + doubleIteration) * (alphaParameter + doubleIteration));
   188→
   189→			denominatorD = 1 + firstTerm * denominatorD;
   190→			if (Math.abs(denominatorD) < epsilon) {
   191→				denominatorD = epsilon;
   192→			}
   193→			numeratorC = 1 + firstTerm / numeratorC;
   194→			if (Math.abs(numeratorC) < epsilon) {
   195→				numeratorC = epsilon;
   196→			}
   197→			denominatorD = 1 / denominatorD;
   198→			resultH *= denominatorD * numeratorC;
   199→
   200→			const secondTerm =
   201→				(-(alphaParameter + iteration) * (sumAlphaBeta + iteration) * inputX) /
   202→				((alphaParameter + doubleIteration) * (alphaPlusOne + doubleIteration));
   203→			denominatorD = 1 + secondTerm * denominatorD;
   204→			if (Math.abs(denominatorD) < epsilon) {
   205→				denominatorD = epsilon;
   206→			}
   207→			numeratorC = 1 + secondTerm / numeratorC;
   208→			if (Math.abs(numeratorC) < epsilon) {
   209→				numeratorC = epsilon;
   210→			}
   211→			denominatorD = 1 / denominatorD;
   212→			const deltaValue = denominatorD * numeratorC;
   213→			resultH *= deltaValue;
   214→
   215→			if (Math.abs(deltaValue - 1) < epsilon) {
   216→				break;
   217→			}
   218→		}
   219→
   220→		return resultH;
   221→	}
   222→
   223→	private static gammaLn(inputValue: number): number {
   224→		const coefficients = [
   225→			76.18009172947146, -86.50532032941677, 24.01409824083091, -1.231739572450155,
   226→			0.1208650973866179e-2, -0.5395239384953e-5,
   227→		];
   228→
   229→		let index = 0;
   230→		let seriesSum = 1.000000000190015;
   231→		const adjustedValue = inputValue;
   232→		let yVariable = adjustedValue;
   233→		let tempValue = adjustedValue + 5.5;
   234→		tempValue -= (adjustedValue + 0.5) * Math.log(tempValue);
   235→
   236→		for (; index < coefficients.length; index++) {
   237→			yVariable += 1;
   238→			const coefficient = coefficients[index] as unknown as number;
   239→			seriesSum += coefficient / yVariable;
   240→		}
   241→
   242→		return -tempValue + Math.log((2.5066282746310005 * seriesSum) / adjustedValue);
   243→	}
   244→
   245→	private static calculateEffectSize(
   246→		group1: { mean: number; variance: number; n: number },
   247→		group2: { mean: number; variance: number; n: number },
   248→	): number {
   249→		if (group1.n <= 1 || group2.n <= 1) return 0;
   250→
   251→		const pooledVariance =
   252→			((group1.n - 1) * group1.variance + (group2.n - 1) * group2.variance) /
   253→			(group1.n + group2.n - 2);
   254→
   255→		const pooledStdDev = Math.sqrt(Math.max(0, pooledVariance));
   256→
   257→		if (pooledStdDev === 0) return 0;
   258→
   259→		return (group2.mean - group1.mean) / pooledStdDev;
   260→	}
   261→
   262→	private static calculateMomentum(trendComponent: number[]): number {
   263→		if (trendComponent.length < 14) return 0;
   264→
   265→		const recentPeriod = Math.min(7, Math.floor(trendComponent.length / 2));
   266→		const mediumPeriod = Math.min(14, trendComponent.length);
   267→
   268→		const recentTrend = trendComponent.slice(-recentPeriod);
   269→		const mediumTrend = trendComponent.slice(-mediumPeriod, -recentPeriod);
   270→
   271→		const recentSlope = this.calculateSlope(recentTrend);
   272→		const mediumSlope = this.calculateSlope(mediumTrend);
   273→
   274→		return recentSlope - mediumSlope;
   275→	}
   276→
   277→	private static calculateSlope(dataValues: number[]): number {
   278→		const dataLength = dataValues.length;
   279→		if (dataLength < 2) return 0;
   280→
   281→		const xCoordinates = Array.from({ length: dataLength }, (_, index) => index);
   282→		const xMean = (dataLength - 1) / 2;
   283→		const yMean = dataValues.reduce((sum, value) => sum + value, 0) / dataLength;
   284→
   285→		let slopeNumerator = 0;
   286→		let slopeDenominator = 0;
   287→
   288→		for (let index = 0; index < dataLength; index++) {
   289→			const xCoordinate = xCoordinates[index] as unknown as number;
   290→			const yCoordinate = dataValues[index] as unknown as number;
   291→			const xDeviation = xCoordinate - xMean;
   292→			const yDeviation = yCoordinate - yMean;
   293→			slopeNumerator += xDeviation * yDeviation;
   294→			slopeDenominator += xDeviation * xDeviation;
   295→		}
   296→
   297→		return slopeDenominator === 0 ? 0 : slopeNumerator / slopeDenominator;
   298→	}
   299→
   300→	private static calculateVolatility(dataValues: number[]): number {
   301→		if (dataValues.length === 0) return 0;
   302→
   303→		const meanValue =
   304→			dataValues.reduce((sum, value) => sum + value, 0) / dataValues.length;
   305→		if (meanValue === 0) return 0;
   306→
   307→		const varianceValue =
   308→			dataValues.reduce((sum, value) => sum + Math.pow(value - meanValue, 2), 0) /
   309→			dataValues.length;
   310→		const standardDeviation = Math.sqrt(varianceValue);
   311→
   312→		return standardDeviation / meanValue;
   313→	}
   314→
   315→	private static applyVolatilityPenalty(
   316→		trendScore: number,
   317→		volatilityValue: number,
   318→	): number {
   319→		const maximumVolatility = 2.0;
   320→		const normalizedVolatility =
   321→			Math.min(volatilityValue, maximumVolatility) / maximumVolatility;
   322→		const volatilityPenalty = normalizedVolatility * 0.3;
   323→
   324→		return trendScore * (1 - volatilityPenalty);
   325→	}
   326→
   327→	private static createEmptyResult(): TrendingScoreResult {
   328→		return {
   329→			trendScore: 0,
   330→			isSignificant: false,
   331→			pValue: 1.0,
   332→			effectSize: 0,
   333→			momentum: 0,
   334→			volatility: 0,
   335→		};
   336→	}
   337→}
