export interface TrendingScoreData {
	historicalOrders: number[];
	forecastedOrders: number[];
	trendComponent: number[];
}

export interface TrendingScoreResult {
	trendScore: number;
	isSignificant: boolean;
	pValue: number;
	effectSize: number;
	momentum: number;
	volatility: number;
}

export class TrendingScoreCalculator {
	private static readonly SIGNIFICANCE_THRESHOLD = 0.05;
	private static readonly MIN_EFFECT_SIZE = 0.3;
	private static readonly MOMENTUM_WEIGHT = 0.6;
	private static readonly SIGNIFICANCE_WEIGHT = 0.4;

	static calculateTrendingScore(data: TrendingScoreData): TrendingScoreResult {
		const { historicalOrders, forecastedOrders, trendComponent } = data;

		if (historicalOrders.length === 0 || forecastedOrders.length === 0) {
			return this.createEmptyResult();
		}

		const historicalStats = this.calculateStatistics(historicalOrders);
		const forecastStats = this.calculateStatistics(forecastedOrders);

		const tTestResult = this.performTTest(historicalStats, forecastStats);
		const effectSize = this.calculateEffectSize(historicalStats, forecastStats);
		const momentum = this.calculateMomentum(trendComponent);
		const volatility = this.calculateVolatility(historicalOrders);

		const isSignificant =
			tTestResult.pValue < this.SIGNIFICANCE_THRESHOLD &&
			Math.abs(effectSize) > this.MIN_EFFECT_SIZE;

		let trendScore = 0;
		if (isSignificant && effectSize > 0) {
			const momentumFactor = Math.max(0, momentum * 20);
			const significanceFactor = Math.max(0, effectSize * 30);

			trendScore =
				momentumFactor * this.MOMENTUM_WEIGHT +
				significanceFactor * this.SIGNIFICANCE_WEIGHT;

			trendScore = this.applyVolatilityPenalty(trendScore, volatility);
		}

		return {
			trendScore: Math.round(Math.max(0, Math.min(100, trendScore)) * 100) / 100,
			isSignificant,
			pValue: tTestResult.pValue,
			effectSize,
			momentum,
			volatility,
		};
	}

	private static calculateStatistics(values: number[]): {
		mean: number;
		variance: number;
		stdDev: number;
		n: number;
	} {
		const n = values.length;
		if (n === 0) {
			return { mean: 0, variance: 0, stdDev: 0, n: 0 };
		}

		const mean = values.reduce((sum, val) => sum + val, 0) / n;
		const variance =
			values.reduce((sum, val) => sum + Math.pow(val - mean, 2), 0) / (n - 1);
		const stdDev = Math.sqrt(Math.max(0, variance));

		return { mean, variance, stdDev, n };
	}

	private static performTTest(
		group1: { mean: number; variance: number; n: number },
		group2: { mean: number; variance: number; n: number },
	): { tStatistic: number; pValue: number } {
		if (group1.n <= 1 || group2.n <= 1) {
			return { tStatistic: 0, pValue: 1.0 };
		}

		const pooledVariance =
			((group1.n - 1) * group1.variance + (group2.n - 1) * group2.variance) /
			(group1.n + group2.n - 2);

		if (pooledVariance <= 0) {
			return { tStatistic: 0, pValue: 1.0 };
		}

		const standardError = Math.sqrt(pooledVariance * (1 / group1.n + 1 / group2.n));
		const tStatistic = (group2.mean - group1.mean) / standardError;
		const degreesOfFreedom = group1.n + group2.n - 2;

		const pValue = this.calculatePValue(Math.abs(tStatistic), degreesOfFreedom);

		return { tStatistic, pValue };
	}

	private static calculatePValue(tStatistic: number, degreesOfFreedom: number): number {
		if (degreesOfFreedom <= 0) return 1.0;
		if (tStatistic === 0) return 1.0;

		const betaDistributionInput =
			degreesOfFreedom / (degreesOfFreedom + tStatistic * tStatistic);

		if (
			betaDistributionInput < 0 ||
			betaDistributionInput > 1 ||
			!Number.isFinite(betaDistributionInput)
		)
			return 1.0;

		const betaValue = this.incompleteBeta(
			betaDistributionInput,
			degreesOfFreedom / 2,
			0.5,
		);

		return Math.max(0, Math.min(1, betaValue));
	}

	private static incompleteBeta(
		inputX: number,
		alphaParameter: number,
		betaParameter: number,
	): number {
		if (inputX <= 0) return 0;
		if (inputX >= 1) return 1;

		const betaFunction = Math.exp(
			this.gammaLn(alphaParameter + betaParameter) -
				this.gammaLn(alphaParameter) -
				this.gammaLn(betaParameter) +
				alphaParameter * Math.log(inputX) +
				betaParameter * Math.log(1 - inputX),
		);

		if (inputX < (alphaParameter + 1) / (alphaParameter + betaParameter + 2)) {
			return (
				(betaFunction *
					this.betaContinuedFraction(inputX, alphaParameter, betaParameter)) /
				alphaParameter
			);
		} else {
			return (
				1 -
				(betaFunction *
					this.betaContinuedFraction(1 - inputX, betaParameter, alphaParameter)) /
					betaParameter
			);
		}
	}

	private static betaContinuedFraction(
		inputX: number,
		alphaParameter: number,
		betaParameter: number,
	): number {
		const maxIterations = 100;
		const epsilon = 3e-7;

		const sumAlphaBeta = alphaParameter + betaParameter;
		const alphaPlusOne = alphaParameter + 1;
		const alphaMinusOne = alphaParameter - 1;
		let numeratorC = 1;
		let denominatorD = 1 - (sumAlphaBeta * inputX) / alphaPlusOne;

		if (Math.abs(denominatorD) < epsilon) {
			denominatorD = epsilon;
		}

		denominatorD = 1 / denominatorD;
		let resultH = denominatorD;

		for (let iteration = 1; iteration <= maxIterations; iteration++) {
			const doubleIteration = 2 * iteration;
			const firstTerm =
				(iteration * (betaParameter - iteration) * inputX) /
				((alphaMinusOne + doubleIteration) * (alphaParameter + doubleIteration));

			denominatorD = 1 + firstTerm * denominatorD;
			if (Math.abs(denominatorD) < epsilon) {
				denominatorD = epsilon;
			}
			numeratorC = 1 + firstTerm / numeratorC;
			if (Math.abs(numeratorC) < epsilon) {
				numeratorC = epsilon;
			}
			denominatorD = 1 / denominatorD;
			resultH *= denominatorD * numeratorC;

			const secondTerm =
				(-(alphaParameter + iteration) * (sumAlphaBeta + iteration) * inputX) /
				((alphaParameter + doubleIteration) * (alphaPlusOne + doubleIteration));
			denominatorD = 1 + secondTerm * denominatorD;
			if (Math.abs(denominatorD) < epsilon) {
				denominatorD = epsilon;
			}
			numeratorC = 1 + secondTerm / numeratorC;
			if (Math.abs(numeratorC) < epsilon) {
				numeratorC = epsilon;
			}
			denominatorD = 1 / denominatorD;
			const deltaValue = denominatorD * numeratorC;
			resultH *= deltaValue;

			if (Math.abs(deltaValue - 1) < epsilon) {
				break;
			}
		}

		return resultH;
	}

	private static gammaLn(inputValue: number): number {
		const coefficients = [
			76.18009172947146, -86.50532032941677, 24.01409824083091, -1.231739572450155,
			0.1208650973866179e-2, -0.5395239384953e-5,
		];

		let index = 0;
		let seriesSum = 1.000000000190015;
		const adjustedValue = inputValue;
		let yVariable = adjustedValue;
		let tempValue = adjustedValue + 5.5;
		tempValue -= (adjustedValue + 0.5) * Math.log(tempValue);

		for (; index < coefficients.length; index++) {
			yVariable += 1;
			const coefficient = coefficients[index] as unknown as number;
			seriesSum += coefficient / yVariable;
		}

		return -tempValue + Math.log((2.5066282746310005 * seriesSum) / adjustedValue);
	}

	private static calculateEffectSize(
		group1: { mean: number; variance: number; n: number },
		group2: { mean: number; variance: number; n: number },
	): number {
		if (group1.n <= 1 || group2.n <= 1) return 0;

		const pooledVariance =
			((group1.n - 1) * group1.variance + (group2.n - 1) * group2.variance) /
			(group1.n + group2.n - 2);

		const pooledStdDev = Math.sqrt(Math.max(0, pooledVariance));

		if (pooledStdDev === 0) return 0;

		return (group2.mean - group1.mean) / pooledStdDev;
	}

	private static calculateMomentum(trendComponent: number[]): number {
		if (trendComponent.length < 14) return 0;

		const recentPeriod = Math.min(7, Math.floor(trendComponent.length / 2));
		const mediumPeriod = Math.min(14, trendComponent.length);

		const recentTrend = trendComponent.slice(-recentPeriod);
		const mediumTrend = trendComponent.slice(-mediumPeriod, -recentPeriod);

		const recentSlope = this.calculateSlope(recentTrend);
		const mediumSlope = this.calculateSlope(mediumTrend);

		return recentSlope - mediumSlope;
	}

	private static calculateSlope(dataValues: number[]): number {
		const dataLength = dataValues.length;
		if (dataLength < 2) return 0;

		const xCoordinates = Array.from({ length: dataLength }, (_, index) => index);
		const xMean = (dataLength - 1) / 2;
		const yMean = dataValues.reduce((sum, value) => sum + value, 0) / dataLength;

		let slopeNumerator = 0;
		let slopeDenominator = 0;

		for (let index = 0; index < dataLength; index++) {
			const xCoordinate = xCoordinates[index] as unknown as number;
			const yCoordinate = dataValues[index] as unknown as number;
			const xDeviation = xCoordinate - xMean;
			const yDeviation = yCoordinate - yMean;
			slopeNumerator += xDeviation * yDeviation;
			slopeDenominator += xDeviation * xDeviation;
		}

		return slopeDenominator === 0 ? 0 : slopeNumerator / slopeDenominator;
	}

	private static calculateVolatility(dataValues: number[]): number {
		if (dataValues.length === 0) return 0;

		const meanValue =
			dataValues.reduce((sum, value) => sum + value, 0) / dataValues.length;
		if (meanValue === 0) return 0;

		const varianceValue =
			dataValues.reduce((sum, value) => sum + Math.pow(value - meanValue, 2), 0) /
			dataValues.length;
		const standardDeviation = Math.sqrt(varianceValue);

		return standardDeviation / meanValue;
	}

	private static applyVolatilityPenalty(
		trendScore: number,
		volatilityValue: number,
	): number {
		const maximumVolatility = 2.0;
		const normalizedVolatility =
			Math.min(volatilityValue, maximumVolatility) / maximumVolatility;
		const volatilityPenalty = normalizedVolatility * 0.3;

		return trendScore * (1 - volatilityPenalty);
	}

	private static createEmptyResult(): TrendingScoreResult {
		return {
			trendScore: 0,
			isSignificant: false,
			pValue: 1.0,
			effectSize: 0,
			momentum: 0,
			volatility: 0,
		};
	}
}

