   703→		const fullSegment = values.slice(start, end);
   704→		const leftSegment = values.slice(start, cp);
   705→		const rightSegment = values.slice(cp, end);
   706→
   707→		if (leftSegment.length < 2 || rightSegment.length < 2) return false;
   708→
   709→		const ll0 = -this.segmentCost(fullSegment, 0, fullSegment.length - 1, method);
   710→		const ll1 =
   711→			-this.segmentCost(leftSegment, 0, leftSegment.length - 1, method) -
   712→			this.segmentCost(rightSegment, 0, rightSegment.length - 1, method);
   713→
   714→		const lrt = 2 * (ll1 - ll0);
   715→
   716→		const df = method === 'meanvar' ? 2 : 1;
   717→
   718→		const criticalValue = this.chiSquareInverse(1 - significance, df);
   719→
