   725→	 * This method constructs segments based on the detected change points.
   726→	 * Each segment contains the start and end indices, mean, and variance of the values in that segment.
   727→	 * Physical meaning: It provides a structured representation of the data segments between change points.
   728→	 */
   729→	private static buildSegments(
   730→		values: number[],
   731→		changePoints: number[],
   732→	): { start: number; end: number; mean: number; variance: number }[] {
   733→		if (values.length === 0) {
   734→			return [{ start: 0, end: 0, mean: 0, variance: 0 }];
   735→		}
   736→
   737→		const segments: { start: number; end: number; mean: number; variance: number }[] = [];
   738→		const allPoints = [0, ...changePoints, values.length];
   739→
   740→		for (let i = 0; i < allPoints.length - 1; i++) {
   741→			const start = allPoints[i];
   742→			const end = allPoints[i + 1];
   743→			if (start !== undefined && end !== undefined) {
   744→				const segment = values.slice(start, end);
   745→
   746→				segments.push({
   747→					start,
   748→					end: end - 1,
   749→					mean: this.mean({ values: segment, precision: null }),
   750→					variance: this.variance({ values: segment, precision: null }),
   751→				});
   752→			}
   753→		}
   754→
   755→		return segments;
   756→	}
   757→
   758→	/**
