export class MathematicalFunctions {
	static roundToPrecision({
		value,
		precision,
	}: {
		value: number;
		precision: number | null;
	}): number {
		if (typeof value !== 'number') {
			throw new Error('Input must be a number');
		}

		if (precision !== null && typeof precision !== 'number') {
			throw new Error('Precision must be a number or null');
		}

		if (precision === null) return value;

		const factor = Math.pow(10, precision);
		return Math.round(value * factor) / factor;
	}

	/**
	 * Calculates the mean of an array of numbers.
	 * Physical meaning: It represents the average value of a set of numbers.
	 */
	static mean({
		values,
		precision,
	}: {
		values: number[];
		precision: number | null;
	}): number {
		if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
			throw new Error('Input must be an array of numbers');
		}

		if (values.length === 0) return 0;
		const mean = values.reduce((sum, val) => sum + val, 0) / values.length;
		return precision ? this.roundToPrecision({ value: mean, precision }) : mean;
	}

	/**
	 * Calculates the median of an array of numbers.
	 * The median is the middle value when the numbers are sorted.
	 * Physical meaning: It represents the central tendency of a set of numbers, less affected by outliers than the mean.
	 */
	static median({ values }: { values: number[] }): number {
		if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
			throw new Error('Input must be an array of numbers');
		}

		if (values.length === 0) {
			throw new Error('Cannot calculate median of empty array');
		}

		const sorted = [...values].sort((a, b) => a - b);
		const mid = Math.floor(sorted.length / 2);

		if (sorted.length % 2 === 0) {
			const midLeft = sorted[mid - 1];
			const midRight = sorted[mid];
			if (midLeft === undefined || midRight === undefined) {
				throw new Error('Unexpected undefined value in sorted array');
			}
			return (midLeft + midRight) / 2;
		} else {
			const midValue = sorted[mid];
			if (midValue === undefined) {
				throw new Error('Unexpected undefined value in sorted array');
			}
			return midValue;
		}
	}

	/**
	 * Calculates the variance of an array of numbers.
	 * Variance is the average of the squared differences from the mean.
	 * Physical meaning: It measures how far a set of numbers are spread out from their average value.
	 */
	static variance({
		values,
		precision,
	}: {
		values: number[];
		precision: number | null;
	}): number {
		if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
			throw new Error('Input must be an array of numbers');
		}

		if (values.length === 0) return 0;
		const meanVal = this.mean({ values, precision });

		if (precision !== null) {
			const value =
				values.reduce((sum, val) => sum + Math.pow(val - meanVal, 2), 0) / values.length;
			return this.roundToPrecision({ value, precision });
		}

		return (
			values.reduce((sum, val) => sum + Math.pow(val - meanVal, 2), 0) / values.length
		);
	}

	/**	 * Calculates the median absolute deviation (MAD) of an array of numbers.
	 * MAD is the median of the absolute deviations from the median.
	 * Physical meaning: It measures the variability of a set of values, robust to outliers.
	 */
	static medianAbsoluteDeviation({ values }: { values: number[] }): number {
		if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
			throw new Error('Input must be an array of numbers');
		}

		if ([0, 1].includes(values.length)) return 0;

		const median = this.median({ values });
		const deviations = values.map((val) => Math.abs(val - median));
		return this.median({ values: deviations });
	}

	/**
	 * Calculates the standard deviation of an array of numbers.
	 * Standard deviation is the square root of the variance.
	 * Physical meaning: It measures the amount of variation or dispersion in a set of values.
	 */
	static standardDeviation({
		values,
		precision,
	}: {
		values: number[];
		precision: number | null;
	}): number {
		if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
			throw new Error('Input must be an array of numbers');
		}

		if (values.length === 0) return 0;
		if (precision !== null) {
			const value = this.variance({ values, precision });
			return this.roundToPrecision({ value: Math.sqrt(value), precision });
		}
		return Math.sqrt(this.variance({ values, precision: null }));
	}

	/**
	 * Calculates the linear regression parameters (slope, intercept, r-squared) for two arrays of numbers.
	 * linear regression is a statistical method to model the relationship between two variables.
	 * It finds the best-fitting line through the data points.
	 * Physical meaning: It helps to understand the relationship between two variables and predict one variable based on the other.
	 */
	static linearRegression({ x, y }: { x: number[]; y: number[] }): {
		slope: number;
		intercept: number;
		rSquared: number;
	} {
		if (!Array.isArray(x) || !Array.isArray(y)) {
			throw new Error('Input must be arrays');
		}

		if (x.length === 0 || y.length === 0) {
			throw new Error('Input arrays must have the same non-zero length');
		}

		if (x.length !== y.length) {
			throw new Error('Input arrays must have the same non-zero length');
		}
		if (
			x.some((val) => typeof val !== 'number') ||
			y.some((val) => typeof val !== 'number')
		) {
			throw new Error('Input arrays must contain only numbers');
		}

		const n = x.length;
		const sumX = x.reduce((sum, val) => sum + val, 0);
		const sumY = y.reduce((sum, val) => sum + val, 0);
		const sumXY = x.reduce((sum, val, i) => sum + val * (y[i] ?? 0), 0);
		const sumXX = x.reduce((sum, val) => sum + val * val, 0);

		const denominator = n * sumXX - sumX * sumX;

		if (Math.abs(denominator) < 1e-10) {
			const yMean = this.mean({ values: y, precision: null });
			return { slope: 0, intercept: yMean, rSquared: 0 };
		}

		const slope = (n * sumXY - sumX * sumY) / denominator;
		const intercept = (sumY - slope * sumX) / n;

		const yMean = this.mean({ values: y, precision: null });
		const totalSumSquares = y.reduce((sum, val) => sum + Math.pow(val - yMean, 2), 0);
		const residualSumSquares = y.reduce((sum, val, i) => {
			const predicted = slope * (x[i] ?? 0) + intercept;
			return sum + Math.pow(val - predicted, 2);
		}, 0);

		const rSquared =
			residualSumSquares === 0 && totalSumSquares === 0
				? 0
				: 1 - residualSumSquares / totalSumSquares;

		return { slope, intercept, rSquared };
	}

	/**
	 * Calculates the moving average of an array of numbers.
	 * The moving average smooths the data by averaging values over a specified window size.
	 * Physical meaning: It helps to identify trends in time series data by reducing noise.
	 */
	static movingAverage({
		values,
		windowSize,
		precision,
	}: {
		values: number[];
		windowSize: number;
		precision: number | null;
	}): number[] {
		if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
			throw new Error('Input must be an array of numbers');
		}

		if (typeof windowSize !== 'number' || windowSize <= 0) {
			throw new Error('Window size must be a positive number');
		}

		if (precision !== null && typeof precision !== 'number') {
			throw new Error('Precision must be a number or null');
		}

		if (values.length === 0) return [];

		if (windowSize <= 0 || windowSize > values.length) {
			throw new Error('Invalid window size');
		}

		const result: number[] = [];

		for (let i = 0; i <= values.length - windowSize; i++) {
			const window = values.slice(i, i + windowSize);
			result.push(this.mean({ values: window, precision }));
		}
		return result;
	}
	/**
	 * Calculates the Fourier coefficients for a given set of values.
	 * Fourier coefficients represent the amplitudes of sine and cosine waves that can reconstruct the original signal.
	 * Physical meaning: They decompose a signal into its frequency components, allowing analysis of periodic patterns.
	 * Read wiki for more info.
	 */
	static fourierCoefficients({
		values,
		period,
		harmonics,
		precision,
	}: {
		values: number[];
		period: number;
		harmonics: number;
		precision: number | null;
	}): {
		a: number[];
		b: number[];
	} {
		if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
			throw new Error('Input must be an array of numbers');
		}
		if (typeof period !== 'number' || period <= 0) {
			throw new Error('Period must be a positive number');
		}
		if (typeof harmonics !== 'number' || harmonics <= 0) {
			throw new Error('Harmonics must be a positive number');
		}
		if (precision !== null && typeof precision !== 'number') {
			throw new Error('Precision must be a number or null');
		}

		if (values.length === 0) return { a: [], b: [] };

		const n = values.length;
		const a: number[] = [];
		const b: number[] = [];

		for (let k = 1; k <= harmonics; k++) {
			let aK = 0;
			let bK = 0;

			for (let t = 0; t < n; t++) {
				const angle = (2 * Math.PI * k * t) / period;
				const val = values[t] ?? 0;
				aK += val * Math.cos(angle);
				bK += val * Math.sin(angle);
			}

			aK = (2 * aK) / n;
			bK = (2 * bK) / n;

			if (precision !== null) {
				aK = this.roundToPrecision({ value: aK, precision });
				bK = this.roundToPrecision({ value: bK, precision });
			}

			a.push(aK);
			b.push(bK);
		}

		return { a, b };
	}

	/**
	 * Reconstructs a Fourier series from the coefficients.
	 * This method uses the Fourier coefficients to reconstruct the original signal.
	 * Physical meaning: It allows the synthesis of a signal from its frequency components.
	 */
	static reconstructFourierSeries({
		period,
		harmonics,
		a,
		b,
		length,
		a0 = 0,
	}: {
		period: number;
		harmonics: number;
		a: number[];
		b: number[];
		length: number;
		a0?: number;
	}): number[] {
		if (typeof period !== 'number' || period <= 0 || !Number.isFinite(period)) {
			throw new Error('Period must be a positive finite number');
		}
		if (period > 1e10) {
			throw new Error('Period is too large and may cause numerical precision issues');
		}
		if (typeof harmonics !== 'number' || harmonics <= 0 || !Number.isInteger(harmonics)) {
			throw new Error('Harmonics must be a positive integer');
		}
		if (!Array.isArray(a) || !Array.isArray(b)) {
			throw new Error('Fourier coefficients must be arrays');
		}

		if (
			a.some((val) => typeof val !== 'number' || !Number.isFinite(val)) ||
			b.some((val) => typeof val !== 'number' || !Number.isFinite(val))
		) {
			throw new Error('Fourier coefficients must contain only finite numbers');
		}

		if (a.length !== harmonics || b.length !== harmonics) {
			throw new Error('Fourier coefficients must have the same length as harmonics');
		}

		if (typeof length !== 'number' || length <= 0) {
			throw new Error('Length must be a positive number');
		}

		if (typeof a0 !== 'number' || !Number.isFinite(a0)) {
			throw new Error('DC component (a0) must be a finite number');
		}

		const result: number[] = [];

		for (let t = 0; t < length; t++) {
			let value = a0;
			for (let k = 1; k <= harmonics; k++) {
				const angle = (2 * Math.PI * k * t) / period;
				value += (a[k - 1] ?? 0) * Math.cos(angle) + (b[k - 1] ?? 0) * Math.sin(angle);
			}
			result.push(value);
		}

		return result;
	}

	/**
	 * Detects change points using PELT algorithm with statistical validation.
	 * Change points are where statistical properties change significantly.
	 * Physical meaning: Identifies structural breaks in time series data.
	 * Based on Killick et al. (2012) "Optimal Detection of Changepoints With a Linear Computational Cost"
	 * cspell:ignore Changepoints meanvar
	 */
	static changePointDetection({
		values,
		minSegmentLength = Math.max(1, Math.floor(values.length * 0.1)),
		penalty = Math.max(Math.log(values.length) * 2, 10e-20),
		method = 'mean' as 'mean' | 'variance' | 'meanvar',
		significance = 0.1,
	}: {
		values: number[];
		minSegmentLength?: number;
		penalty?: number;
		method?: 'mean' | 'variance' | 'meanvar';
		significance?: number;
	}): {
		changePoints: number[];
		cost: number;
		segments: { start: number; end: number; mean: number; variance: number }[];
	} {
		if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
			throw new Error('Input must be an array of numbers');
		}

		if (
			typeof minSegmentLength !== 'number' ||
			minSegmentLength < 1 ||
			!Number.isInteger(minSegmentLength)
		) {
			throw new Error('Minimum segment length must be at least 1');
		}

		if (typeof penalty !== 'number' || penalty < 0) {
			throw new Error('Penalty must be a non-negative number');
		}

		if (!['mean', 'variance', 'meanvar'].includes(method)) {
			throw new Error(`Unknown method: ${method}`);
		}

		if (typeof significance !== 'number' || significance <= 0 || significance >= 1) {
			throw new Error('Significance level must be between 0 and 1');
		}

		if (values.length === 0) {
			return { changePoints: [], cost: 0, segments: [] };
		}

		if (values.length < minSegmentLength * 2) {
			return {
				changePoints: [],
				cost: this.segmentCost(values, 0, values.length - 1, method),
				segments: [
					{
						start: 0,
						end: values.length - 1,
						mean: this.mean({ values, precision: null }),
						variance: this.variance({ values, precision: null }),
					},
				],
			};
		}

		const dataLength = values.length;
		const optimalCosts: number[] = Array.from({ length: dataLength + 1 }, () => Infinity);
		const lastChangePoints: number[] = Array.from({ length: dataLength + 1 }, () => -1);

		optimalCosts[0] = 0;

		for (let timePoint = minSegmentLength; timePoint <= dataLength; timePoint++) {
			let bestCost = Infinity;
			let bestChangePoint = -1;

			for (
				let previousChangePoint = 0;
				previousChangePoint <= timePoint - minSegmentLength;
				previousChangePoint++
			) {
				const currentOptimalCost = optimalCosts[previousChangePoint];
				if (currentOptimalCost !== undefined && currentOptimalCost !== Infinity) {
					const segmentCost = this.segmentCost(
						values,
						previousChangePoint,
						timePoint - 1,
						method,
					);
					const totalCost = currentOptimalCost + segmentCost + penalty;

					if (totalCost < bestCost) {
						bestCost = totalCost;
						bestChangePoint = previousChangePoint;
					}
				}
			}

			if (bestChangePoint !== -1) {
				optimalCosts[timePoint] = bestCost;
				lastChangePoints[timePoint] = bestChangePoint;
			}
		}

		const changePoints: number[] = [];
		let currentPosition = dataLength;
		let lastChangePoint = lastChangePoints[currentPosition];
		while (
			lastChangePoint !== undefined &&
			lastChangePoint !== -1 &&
			lastChangePoint !== 0
		) {
			changePoints.unshift(lastChangePoint);
			currentPosition = lastChangePoint;
			lastChangePoint = lastChangePoints[currentPosition];
		}

		const validatedChangePoints = this.validateChangePoints(
			values,
			changePoints,
			significance,
			method,
		);

		const segments = this.buildSegments(values, validatedChangePoints);

		const finalCost = optimalCosts[dataLength];
		return {
			changePoints: validatedChangePoints,
			cost: finalCost ?? Infinity,
			segments,
		};
	}

	/**
	 * Applies exponential smoothing to an array of numbers.
	 * Exponential smoothing is a time series forecasting method for univariate data.
	 * Physical meaning: It gives more weight to recent observations, making it useful for forecasting.
	 */
	static exponentialSmoothing({
		values,
		alpha = 0.3,
	}: {
		values: number[];
		alpha?: number;
	}): number[] {
		if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
			throw new Error('Input must be an array of numbers');
		}

		if (typeof alpha !== 'number' || alpha < 0 || alpha > 1) {
			throw new Error('Alpha must be a number between 0 and 1');
		}

		if (values.length === 0) return [];

		const firstValue = values[0];
		if (firstValue === undefined) return [];

		const result: number[] = [firstValue];
		for (let i = 1; i < values.length; i++) {
			const currentValue = values[i] ?? 0;
			const previousResult = result[i - 1] ?? 0;
			const smoothed = alpha * currentValue + (1 - alpha) * previousResult;
			result.push(smoothed);
		}

		return result;
	}

	/**
	 * Calculates the trend line using linear regression.
	 * The trend line represents the general direction of the data over time.
	 * Physical meaning: It helps to identify long-term trends in time series data.
	 */
	static calculateTrend({
		values,
		dates,
	}: {
		values: number[];
		dates: string[];
	}): number[] {
		if (!Array.isArray(values) || !Array.isArray(dates)) {
			throw new Error('Input must be arrays');
		}

		if (values.length === 0 || dates.length === 0) {
			return [];
		}

		if (values.some((val) => typeof val !== 'number')) {
			throw new Error('Values array must contain only numbers');
		}

		if (dates.some((date) => typeof date !== 'string')) {
			throw new Error('Dates array must contain only strings');
		}

		if (dates.length !== values.length) {
			throw new Error('Values and dates arrays must have the same length');
		}

		if (dates.some((date) => isNaN(new Date(date).getTime()))) {
			throw new Error('All dates must be valid date strings');
		}

		const timestamps = dates.map((date) => new Date(date).getTime());
		const baseTime = timestamps[0] as unknown as number;
		const x = timestamps.map((t) => (t - baseTime) / (1000 * 60 * 60 * 24));

		const { slope, intercept } = this.linearRegression({ x, y: values });
		return x.map((t) => slope * t + intercept);
	}

	/**
	 * Removes outliers from an array of numbers using z-score method.
	 * Outliers are values that deviate significantly from the mean.
	 * Physical meaning: It helps to clean the data by removing extreme values that may skew analysis.
	 */
	static removeOutliers({
		values,
		threshold = 2.5,
	}: {
		values: number[];
		threshold?: number;
	}): number[] {
		if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
			throw new Error('Input must be an array of numbers');
		}

		if (threshold && typeof threshold !== 'number') {
			throw new Error('Threshold must be a number');
		}

		if (values.length < 3) return values; // Insufficient data

		const median = this.median({ values });
		const mad = this.medianAbsoluteDeviation({ values });

		return values.map((val) => {
			const modifiedZScore = (0.6745 * Math.abs(val - median)) / mad;
			return modifiedZScore > threshold ? median : val;
		});
	}

	/**
	 * Calculate cost of a segment based on negative log-likelihood
	 * This method calculates the cost of a segment based on the negative log-likelihood of the data.
	 * Physical meaning: It quantifies how well the segment fits a statistical model, with lower costs indicating better fit.
	 * Based on Killick et al. (2012) "Optimal Detection of Changepoints With a Linear Computational Cost"
	 */
	private static segmentCost(
		values: number[],
		start: number,
		end: number,
		method: string,
	): number {
		const segment = values.slice(start, end + 1);
		const n = segment.length;
		if (n === 0) return Infinity;
		if (n === 1) return 0;

		const variance = this.variance({ values: segment, precision: null });

		switch (method) {
			case 'mean':
				return variance === 0 ? 0 : n * Math.log(Math.max(variance, 1e-10));
			case 'variance':
			case 'meanvar':
				return variance === 0
					? 0
					: n * Math.log(Math.max(2 * Math.PI * variance, 1e-10)) + n;
			default:
				throw new Error(`Unknown method: ${method}`);
		}
	}

	/**
	 * Validate change points using likelihood ratio test
	 * This method checks if the detected change points are statistically significant.
	 * It uses the likelihood ratio test to determine if the change points represent significant shifts in the data.
	 * Physical meaning: It ensures that the detected change points are not due to random fluctuations in the data.
	 * Based on Killick et al. (2012) "Optimal Detection of Changepoints With a Linear Computational Cost"
	 */
	private static validateChangePoints(
		values: number[],
		changePoints: number[],
		significance: number,
		method: string,
	): number[] {
		const validated: number[] = [];

		for (let i = 0; i < changePoints.length; i++) {
			const cp = changePoints[i];
			if (cp !== undefined) {
				const start = i === 0 ? 0 : (changePoints[i - 1] ?? 0);
				const end =
					i === changePoints.length - 1
						? values.length
						: (changePoints[i + 1] ?? values.length);

				if (this.isSignificantChangePoint(values, start, cp, end, significance, method)) {
					validated.push(cp);
				}
			}
		}

		return validated;
	}

	/**
	 * Test statistical significance using likelihood ratio
	 * This method checks if the change point is statistically significant
	 * by comparing the log-likelihoods of the segments before and after the change point.
	 * Physical meaning: It determines if a change point represents a significant shift in the data distribution.
	 * Based on Killick et al. (2012) "Optimal Detection of Changepoints With a Linear Computational Cost"
	 */
	private static isSignificantChangePoint(
		values: number[],
		start: number,
		cp: number,
		end: number,
		significance: number,
		method: string,
	): boolean {
		const fullSegment = values.slice(start, end);
		const leftSegment = values.slice(start, cp);
		const rightSegment = values.slice(cp, end);

		if (leftSegment.length < 2 || rightSegment.length < 2) return false;

		const ll0 = -this.segmentCost(fullSegment, 0, fullSegment.length - 1, method);
		const ll1 =
			-this.segmentCost(leftSegment, 0, leftSegment.length - 1, method) -
			this.segmentCost(rightSegment, 0, rightSegment.length - 1, method);

		const lrt = 2 * (ll1 - ll0);

		const df = method === 'meanvar' ? 2 : 1;

		const criticalValue = this.chiSquareInverse(1 - significance, df);

		return lrt > criticalValue;
	}

	/**
	 * Build segments from change points
	 * This method constructs segments based on the detected change points.
	 * Each segment contains the start and end indices, mean, and variance of the values in that segment.
	 * Physical meaning: It provides a structured representation of the data segments between change points.
	 */
	private static buildSegments(
		values: number[],
		changePoints: number[],
	): { start: number; end: number; mean: number; variance: number }[] {
		if (values.length === 0) {
			return [{ start: 0, end: 0, mean: 0, variance: 0 }];
		}

		const segments: { start: number; end: number; mean: number; variance: number }[] = [];
		const allPoints = [0, ...changePoints, values.length];

		for (let i = 0; i < allPoints.length - 1; i++) {
			const start = allPoints[i];
			const end = allPoints[i + 1];
			if (start !== undefined && end !== undefined) {
				const segment = values.slice(start, end);

				segments.push({
					start,
					end: end - 1,
					mean: this.mean({ values: segment, precision: null }),
					variance: this.variance({ values: segment, precision: null }),
				});
			}
		}

		return segments;
	}

	/**
	 * Approximation of inverse chi-square CDF
	 * This method approximates the inverse of the chi-square cumulative distribution function.
	 * It is used to determine critical values for statistical tests.
	 * Physical meaning: It provides a way to find the threshold for significance testing in chi-square
	 */
	private static chiSquareInverse(p: number, df: number): number {
		if (p <= 0 || p >= 1) throw new Error('p must be in (0,1)');
		if (df <= 0) throw new Error('df must be positive');

		// Standard normal quantile (approximation)
		const z = this.normalInverse(p);

		// Wilson-Hilferty transformation (cspell:ignore Hilferty)
		const h = 2 / (9 * df);
		const term = 1 - h + z * Math.sqrt(h);

		return df * Math.pow(Math.max(0, term), 3);
	}

	private static normalInverse(p: number): number {
		if (p <= 0 || p >= 1) throw new Error('p must be in (0,1)');
		if (p === 0.5) return 0;

		const a: [number, number, number, number, number, number, number] = [
			0, -3.969683028665376e1, 2.209460984245205e2, -2.759285104469687e2,
			1.38357751867269e2, -3.066479806614716e1, 2.506628277459239,
		];

		const b: [number, number, number, number, number, number] = [
			0, -5.447609879822406e1, 1.615858368580409e2, -1.556989798598866e2,
			6.680131188771972e1, -1.328068155288572e1,
		];

		const c: [number, number, number, number, number, number, number] = [
			0, -7.784894002430293e-3, -3.223964580411365e-1, -2.400758277161838,
			-2.549732539343734, 4.374664141464968, 2.938163982698783,
		];

		const d: [number, number, number, number, number] = [
			0, 7.784695709041462e-3, 3.224671290700398e-1, 2.445134137142996, 3.754408661907416,
		];

		const q = p < 0.5 ? p : 1 - p;

		let result: number;

		if (q > 1.28e-3) {
			const t = Math.sqrt(-2 * Math.log(q));
			result =
				(((((c[6] * t + c[5]) * t + c[4]) * t + c[3]) * t + c[2]) * t + c[1]) * t + c[0];
			result /= (((d[4] * t + d[3]) * t + d[2]) * t + d[1]) * t + 1;
		} else {
			const t = q * q;
			result =
				q * (((((a[6] * t + a[5]) * t + a[4]) * t + a[3]) * t + a[2]) * t + a[1]) * t +
				a[0];
			result /= ((((b[5] * t + b[4]) * t + b[3]) * t + b[2]) * t + b[1]) * t + 1;
		}

		return p < 0.5 ? -result : result;
	}
}

