import { HolidayHelpers, isUSHoliday, HolidayInfo } from '@utils/holiday-helpers.util';

// Helper function to create dates in local timezone to match the utility's behavior
const createLocalDate = (year: number, month: number, day: number): Date => {
	return new Date(year, month - 1, day, 12, 0, 0); // month is 0-indexed, set to noon
};

describe('Holiday Helpers', () => {
	describe('isUSHoliday (both static method and standalone function)', () => {
		describe('Fixed Date Holidays', () => {
			describe("New Year's Day (January 1)", () => {
				it("should return true for New Year's Day in different years", () => {
					expect(HolidayHelpers.isUSHoliday(createLocalDate(2020, 1, 1))).toBe(true);
					expect(HolidayHelpers.isUSHoliday(createLocalDate(2024, 1, 1))).toBe(true);
					expect(HolidayHelpers.isUSHoliday(createLocalDate(2025, 1, 1))).toBe(true);

					// Test backward compatibility function
					expect(isUSHoliday(createLocalDate(2024, 1, 1))).toBe(true);
					expect(isUSHoliday(createLocalDate(2025, 1, 1))).toBe(true);
				});
			});

			describe('Independence Day (July 4)', () => {
				it('should return true for Independence Day in different years', () => {
					expect(HolidayHelpers.isUSHoliday(createLocalDate(2020, 7, 4))).toBe(true);
					expect(HolidayHelpers.isUSHoliday(createLocalDate(2024, 7, 4))).toBe(true);
					expect(HolidayHelpers.isUSHoliday(createLocalDate(2025, 7, 4))).toBe(true);
				});
			});

			describe('Christmas Day (December 25)', () => {
				it('should return true for Christmas Day in different years', () => {
					expect(HolidayHelpers.isUSHoliday(createLocalDate(2020, 12, 25))).toBe(true);
					expect(HolidayHelpers.isUSHoliday(createLocalDate(2024, 12, 25))).toBe(true);
					expect(HolidayHelpers.isUSHoliday(createLocalDate(2025, 12, 25))).toBe(true);
				});
			});
		});

		describe('Dynamic Date Holidays', () => {
			describe('Martin Luther King Jr. Day (Third Monday in January)', () => {
				it('should return true for MLK Day in different years', () => {
					expect(HolidayHelpers.isUSHoliday(createLocalDate(2024, 1, 15))).toBe(true);
					expect(HolidayHelpers.isUSHoliday(createLocalDate(2025, 1, 20))).toBe(true);
				});
			});

			describe('Thanksgiving (Fourth Thursday in November)', () => {
				it('should return true for Thanksgiving in different years', () => {
					expect(HolidayHelpers.isUSHoliday(createLocalDate(2024, 11, 28))).toBe(true);
					expect(HolidayHelpers.isUSHoliday(createLocalDate(2025, 11, 27))).toBe(true);
				});
			});
		});

		describe('Non-Holiday Days', () => {
			it('should return false for regular weekdays', () => {
				expect(HolidayHelpers.isUSHoliday(createLocalDate(2024, 3, 15))).toBe(false);
				expect(HolidayHelpers.isUSHoliday(createLocalDate(2024, 8, 7))).toBe(false);
			});
		});

		describe('Input validation', () => {
			it('should handle invalid dates gracefully', () => {
				expect(HolidayHelpers.isUSHoliday(new Date('invalid-date'))).toBe(false);
				expect(HolidayHelpers.isUSHoliday(new Date(''))).toBe(false);
			});
		});
	});

	describe('getHolidayInfo', () => {
		it('should return holiday info for valid holidays', () => {
			const christmasInfo = HolidayHelpers.getHolidayInfo(createLocalDate(2024, 12, 25));
			expect(christmasInfo).toBeTruthy();
			expect(christmasInfo?.name).toBe('Christmas Day');
			expect(christmasInfo?.date).toBe('2024-12-25');
			expect(christmasInfo?.type).toBe('public');
		});

		it('should return null for non-holidays', () => {
			const nonHoliday = HolidayHelpers.getHolidayInfo(createLocalDate(2024, 3, 15));
			expect(nonHoliday).toBeNull();
		});

		it('should handle invalid dates gracefully', () => {
			const invalidDate = HolidayHelpers.getHolidayInfo(new Date('invalid'));
			expect(invalidDate).toBeNull();
		});

		// CRITICAL: Test specific branches in getHolidayInfo
		it('should handle edge case in date formatting', () => {
			// Test with a valid date to ensure normal operation
			const result = HolidayHelpers.getHolidayInfo(createLocalDate(2024, 12, 25));
			expect(result).toBeTruthy();
			expect(result?.date).toBe('2024-12-25');
		});

		// CRITICAL: Additional edge case tests to improve branch coverage
		it('should handle various edge cases in date processing', () => {
			// Test with dates that might trigger different code paths
			const edgeDates = [
				createLocalDate(1999, 12, 31), // Y2K edge
				createLocalDate(2000, 1, 1), // Millennium
				createLocalDate(2024, 2, 29), // Leap year
				createLocalDate(2100, 2, 28), // Non-leap century year
			];

			edgeDates.forEach((date) => {
				expect(() => {
					const result = HolidayHelpers.getHolidayInfo(date);
					expect(typeof result).toBe(typeof result); // Just ensure it doesn't throw
				}).not.toThrow();
			});
		});

		it('should cover line 87 by forcing error in date processing with malformed dates', () => {
			const invalidDates = [new Date(NaN), new Date(''), new Date('not-a-date')];

			invalidDates.forEach((invalidDate) => {
				const result = HolidayHelpers.getHolidayInfo(invalidDate);
				expect(result).toBeNull();
			});
		});

		it('should cover line 87 by throwing error during getHolidayInfo execution', () => {
			const testDate = createLocalDate(2024, 12, 25);
			const originalToISOString = Date.prototype.toISOString;

			Date.prototype.toISOString = function (): string {
				throw new Error('Forced error in toISOString');
			};

			const result = HolidayHelpers.getHolidayInfo(testDate);
			expect(result).toBeNull();

			Date.prototype.toISOString = originalToISOString;
		});

		// CRITICAL: Tests specifically designed to trigger catch block at line 87
		it('should trigger catch block for date processing errors', () => {
			// Test with invalid dates that will cause errors in date processing
			const invalidDates = [new Date(NaN), new Date('invalid-date'), new Date('')];

			invalidDates.forEach((date) => {
				const result = HolidayHelpers.getHolidayInfo(date);
				expect(result).toBeNull(); // Should return null from catch block
			});
		});
	});

	describe('getHolidayEffectMultiplier', () => {
		it('should return correct multipliers for major holidays', () => {
			// Christmas should have 2.5x multiplier
			const christmasMultiplier = HolidayHelpers.getHolidayEffectMultiplier(
				createLocalDate(2024, 12, 25),
			);
			expect(christmasMultiplier).toBe(2.5);

			// Independence Day should have 1.4x multiplier
			const july4Multiplier = HolidayHelpers.getHolidayEffectMultiplier(
				createLocalDate(2024, 7, 4),
			);
			expect(july4Multiplier).toBe(1.4);

			// New Year should have 1.5x multiplier
			const newYearMultiplier = HolidayHelpers.getHolidayEffectMultiplier(
				createLocalDate(2025, 1, 1),
			);
			expect(newYearMultiplier).toBe(1.5);
		});

		it('should return 1.2x multiplier for general holidays', () => {
			// Veterans Day should get the general multiplier (line 104)
			const veteransMultiplier = HolidayHelpers.getHolidayEffectMultiplier(
				createLocalDate(2024, 11, 11),
			);
			expect(veteransMultiplier).toBe(1.2);
		});

		it('should cover lines 104-107 default multiplier and catch block', () => {
			const mlkMultiplier = HolidayHelpers.getHolidayEffectMultiplier(
				createLocalDate(2024, 1, 15),
			);
			expect(mlkMultiplier).toBe(1.2);

			const presidentsMultiplier = HolidayHelpers.getHolidayEffectMultiplier(
				createLocalDate(2024, 2, 19),
			);
			expect(presidentsMultiplier).toBe(1.2);

			const columbusMultiplier = HolidayHelpers.getHolidayEffectMultiplier(
				createLocalDate(2024, 10, 14),
			);
			expect(columbusMultiplier).toBe(1.2);

			const invalidDates = [new Date(NaN), new Date('bad-date'), new Date('')];
			invalidDates.forEach((invalidDate) => {
				const result = HolidayHelpers.getHolidayEffectMultiplier(invalidDate);
				expect(result).toBe(1.0);
			});
		});

		it('should cover line 107 by throwing error during getHolidayEffectMultiplier execution', () => {
			const testDate = createLocalDate(2024, 12, 25);

			jest.spyOn(HolidayHelpers, 'getHolidayInfo').mockImplementation(() => {
				throw new Error('Forced error in getHolidayInfo');
			});

			const result = HolidayHelpers.getHolidayEffectMultiplier(testDate);
			expect(result).toBe(1.0);

			jest.restoreAllMocks();
		});

		it('should return 1.0 for non-holidays', () => {
			const nonHolidayMultiplier = HolidayHelpers.getHolidayEffectMultiplier(
				createLocalDate(2024, 3, 15),
			);
			expect(nonHolidayMultiplier).toBe(1.0);
		});

		// CRITICAL: Tests specifically designed to trigger catch block at lines 106-107
		it('should trigger catch block in getHolidayEffectMultiplier', () => {
			// Test with invalid dates to trigger catch block
			const invalidDates = [new Date(NaN), new Date('invalid-date'), new Date('')];

			invalidDates.forEach((date) => {
				const result = HolidayHelpers.getHolidayEffectMultiplier(date);
				expect(result).toBe(1.0); // Should return 1.0 from catch block
			});
		});
	});

	describe('isWithinHolidayWindow', () => {
		it('should detect holidays within default 3-day window', () => {
			// Day before Christmas
			const beforeChristmas = HolidayHelpers.isWithinHolidayWindow(
				createLocalDate(2024, 12, 24),
			);
			expect(beforeChristmas.isWithinWindow).toBe(true);
			expect(beforeChristmas.daysFromHoliday).toBe(1);
			expect(beforeChristmas.holidayName).toBe('Christmas Day');
			expect(beforeChristmas.effectMultiplier).toBe(2.5);
		});

		it('should respect custom window sizes', () => {
			// 1-day window should not detect 2 days before
			const shortWindow = HolidayHelpers.isWithinHolidayWindow(
				createLocalDate(2024, 12, 23),
				1,
			);
			expect(shortWindow.isWithinWindow).toBe(false);

			// 5-day window should detect 4 days before
			const longWindow = HolidayHelpers.isWithinHolidayWindow(
				createLocalDate(2024, 12, 21),
				5,
			);
			expect(longWindow.isWithinWindow).toBe(true);
			expect(longWindow.daysFromHoliday).toBe(4);
		});

		it('should return false for dates outside holiday windows', () => {
			const farFromHoliday = HolidayHelpers.isWithinHolidayWindow(
				createLocalDate(2024, 3, 15),
			);
			expect(farFromHoliday.isWithinWindow).toBe(false);
			expect(farFromHoliday.daysFromHoliday).toBe(0);
			expect(farFromHoliday.holidayName).toBe('');
			expect(farFromHoliday.effectMultiplier).toBe(1.0);
		});

		it('should prioritize the closest holiday', () => {
			// On the holiday itself
			const onHoliday = HolidayHelpers.isWithinHolidayWindow(
				createLocalDate(2024, 12, 25),
			);
			expect(onHoliday.isWithinWindow).toBe(true);
			expect(onHoliday.daysFromHoliday).toBe(0);
			expect(onHoliday.holidayName).toBe('Christmas Day');
		});

		// CRITICAL: Tests specifically designed to trigger catch block at lines 139-146
		it('should trigger catch block in isWithinHolidayWindow', () => {
			// Test with invalid dates to trigger catch block
			const invalidDates = [new Date(NaN), new Date('invalid-date'), new Date('')];

			invalidDates.forEach((date) => {
				const result = HolidayHelpers.isWithinHolidayWindow(date);
				expect(result.isWithinWindow).toBe(false);
				expect(result.effectMultiplier).toBe(1.0);
			});
		});

		it('should throw an error inside isWithinHolidayWindow and be caught and check return value', () => {
			const originalGetHolidayInfo = HolidayHelpers.getHolidayInfo;
			(HolidayHelpers as any).getHolidayInfo = () => {
				throw new Error('Simulated error');
			};

			const result = HolidayHelpers.isWithinHolidayWindow(createLocalDate(2024, 12, 25));
			expect(result.isWithinWindow).toBe(false);
			expect(result.daysFromHoliday).toBe(0);
			expect(result.holidayName).toBe('');
			expect(result.effectMultiplier).toBe(1.0);

			// Restore original method
			(HolidayHelpers as any).getHolidayInfo = originalGetHolidayInfo;
		});
	});

	describe('getHolidaysForYear', () => {
		it('should return all holidays for a given year', () => {
			const holidays2024 = HolidayHelpers.getHolidaysForYear(2024);
			expect(holidays2024.length).toBeGreaterThan(8); // Should have at least major federal holidays

			// Check that major holidays are included
			const holidayNames = holidays2024.map((h) => h.name);
			expect(holidayNames).toContain("New Year's Day");
			expect(holidayNames).toContain('Independence Day');
			expect(holidayNames).toContain('Christmas Day');
		});

		it('should return holidays sorted by date', () => {
			const holidays2024 = HolidayHelpers.getHolidaysForYear(2024);

			// Check that dates are in ascending order
			for (let i = 1; i < holidays2024.length; i++) {
				const prevHoliday = holidays2024[i - 1];
				const currHoliday = holidays2024[i];
				if (prevHoliday && currHoliday) {
					const prevDate = new Date(prevHoliday.date);
					const currDate = new Date(currHoliday.date);
					expect(currDate.getTime()).toBeGreaterThanOrEqual(prevDate.getTime());
				}
			}
		});

		it('should not return duplicate holidays', () => {
			const holidays2024 = HolidayHelpers.getHolidaysForYear(2024);
			const uniqueHolidays = new Set(holidays2024.map((h) => `${h.name}-${h.date}`));
			expect(holidays2024.length).toBe(uniqueHolidays.size);
		});

		// CRITICAL: Tests specifically designed to trigger catch block at lines 173-174
		it('should trigger catch block in getHolidaysForYear', () => {
			// Test with edge case years that may cause issues
			const edgeYears = [0, 1800]; // Very early years that might cause library issues

			edgeYears.forEach((year) => {
				const result = HolidayHelpers.getHolidaysForYear(year);
				expect(Array.isArray(result)).toBe(true);
				// Result could be empty array or contain holidays depending on year
			});
		});

		it('should cover line 174 by triggering error during year processing', () => {
			let callCount = 0;

			jest.spyOn(HolidayHelpers, 'getHolidayInfo').mockImplementation(() => {
				callCount++;
				if (callCount > 5) {
					throw new Error('Simulated error in getHolidayInfo');
				}
				return null;
			});

			const result = HolidayHelpers.getHolidaysForYear(2024);
			expect(Array.isArray(result)).toBe(true);
			expect(result.length).toBe(0);

			jest.restoreAllMocks();
		});
	});

	describe('getHolidayEffect', () => {
		it('should return multiplied effect for holidays', () => {
			const christmasEffect = HolidayHelpers.getHolidayEffect(
				createLocalDate(2024, 12, 25),
			);
			expect(christmasEffect).toBeGreaterThan(1.0);
			expect(christmasEffect).toBeLessThanOrEqual(2.5);
		});

		it('should return diminishing effect based on distance', () => {
			const onChristmas = HolidayHelpers.getHolidayEffect(createLocalDate(2024, 12, 25));
			const dayBefore = HolidayHelpers.getHolidayEffect(createLocalDate(2024, 12, 24));
			const twoDaysBefore = HolidayHelpers.getHolidayEffect(
				createLocalDate(2024, 12, 23),
			);

			expect(onChristmas).toBeGreaterThan(dayBefore);
			expect(dayBefore).toBeGreaterThan(twoDaysBefore);
		});

		it('should return 1.0 for non-holidays', () => {
			const nonHolidayEffect = HolidayHelpers.getHolidayEffect(
				createLocalDate(2024, 3, 15),
			);
			expect(nonHolidayEffect).toBe(1.0);
		});
	});

	describe('isBlackFriday', () => {
		it('should correctly identify Black Friday dates', () => {
			// Black Friday dates (day after Thanksgiving)
			expect(HolidayHelpers.isBlackFriday(createLocalDate(2024, 11, 29))).toBe(true);
			expect(HolidayHelpers.isBlackFriday(createLocalDate(2025, 11, 28))).toBe(true);
		});

		it('should return false for other Fridays in November', () => {
			expect(HolidayHelpers.isBlackFriday(createLocalDate(2024, 11, 1))).toBe(false);
			expect(HolidayHelpers.isBlackFriday(createLocalDate(2024, 11, 8))).toBe(false);
		});

		it('should return false for non-Friday dates', () => {
			expect(HolidayHelpers.isBlackFriday(createLocalDate(2024, 11, 30))).toBe(false); // Saturday after Black Friday
			expect(HolidayHelpers.isBlackFriday(createLocalDate(2024, 3, 15))).toBe(false); // Random date
		});

		it('should handle various years and edge cases for Black Friday calculation', () => {
			const testCases = [
				{ year: 2020, blackFriday: '2020-11-27' },
				{ year: 2021, blackFriday: '2021-11-26' },
				{ year: 2022, blackFriday: '2022-11-25' },
				{ year: 2023, blackFriday: '2023-11-24' },
			];

			testCases.forEach(({ blackFriday }) => {
				const [dateYear, dateMonth, dateDay] = blackFriday.split('-').map(Number) as [
					number,
					number,
					number,
				];
				const blackFridayDate = createLocalDate(dateYear, dateMonth, dateDay);
				expect(HolidayHelpers.isBlackFriday(blackFridayDate)).toBe(true);

				const dayBefore = createLocalDate(dateYear, dateMonth, dateDay - 1);
				expect(HolidayHelpers.isBlackFriday(dayBefore)).toBe(false);

				const dayAfter = createLocalDate(dateYear, dateMonth, dateDay + 1);
				expect(HolidayHelpers.isBlackFriday(dayAfter)).toBe(false);
			});

			expect(HolidayHelpers.isBlackFriday(new Date('invalid'))).toBe(false);
		});

		it('should trigger catch block in isBlackFriday for invalid dates', () => {
			const originalGetTime = Date.prototype.getTime;
			Date.prototype.getTime = function () {
				throw new Error('Simulated error');
			};

			const result = HolidayHelpers.isBlackFriday(new Date());
			expect(result).toBe(false);

			Date.prototype.getTime = originalGetTime;
		});

		it('should cover line 207 safety check when finding first Thursday fails', () => {
			const mockDate = new Date(2024, 10, 1);

			const originalGetDay = Date.prototype.getDay;
			let callCount = 0;

			Date.prototype.getDay = function (this: Date): number {
				if (
					this.getFullYear() === 2024 &&
					this.getMonth() === 10 &&
					this.getDate() <= 7
				) {
					callCount++;
					if (callCount > 10) {
						return 4;
					}
					return 0;
				}
				return originalGetDay.call(this);
			};

			const result = HolidayHelpers.isBlackFriday(mockDate);
			expect(result).toBe(false);

			Date.prototype.getDay = originalGetDay;
		});
	});

	describe('formatHolidayData', () => {
		it('should format holiday data correctly', () => {
			const holidays: HolidayInfo[] = [
				{
					name: 'Christmas Day',
					date: '2024-12-25',
					type: 'public',
					start: createLocalDate(2024, 12, 25),
					end: createLocalDate(2024, 12, 25),
				},
				{
					name: "New Year's Day",
					date: '2025-01-01',
					type: 'public',
					start: createLocalDate(2025, 1, 1),
					end: createLocalDate(2025, 1, 1),
				},
			];

			const formatted = HolidayHelpers.formatHolidayData(holidays);

			expect(formatted).toHaveLength(2);
			expect(formatted[0]).toEqual({
				date: '2024-12-25',
				effect_window: 6,
				impact_multiplier: 2.5, // Christmas multiplier
				name: 'Christmas Day',
			});
		});

		it('should handle empty holiday array', () => {
			const formatted = HolidayHelpers.formatHolidayData([]);
			expect(formatted).toEqual([]);
		});

		it('should handle invalid date formats gracefully', () => {
			const holidays: HolidayInfo[] = [
				{
					name: 'Invalid Holiday',
					date: 'invalid-date',
					type: 'public',
					start: new Date('invalid'),
					end: new Date('invalid'),
				},
			];

			const formatted = HolidayHelpers.formatHolidayData(holidays);
			expect(formatted).toHaveLength(1);
			expect(formatted[0]).toEqual({
				date: 'invalid-date',
				effect_window: 6,
				impact_multiplier: 1.0,
				name: 'Invalid Holiday',
			});
		});
	});

	describe('Integration tests', () => {
		it('should work consistently across different methods', () => {
			const christmasDate = createLocalDate(2024, 12, 25);

			// All methods should recognize Christmas
