			expect(HolidayHelpers.getHolidayEffectMultiplier(regularDate)).toBe(1.0);
			expect(HolidayHelpers.getHolidayEffect(regularDate)).toBe(1.0);

			const window = HolidayHelpers.isWithinHolidayWindow(regularDate);
			expect(window.isWithinWindow).toBe(false);
		});

		// CRITICAL: Additional tests to ensure all catch blocks are covered
		it('should handle all edge cases that trigger catch blocks', () => {
			const edgeCaseDates = [new Date(NaN), new Date('invalid'), new Date('')];

			edgeCaseDates.forEach((date) => {
				// Ensure all methods handle edge cases gracefully
				expect(typeof HolidayHelpers.isUSHoliday(date)).toBe('boolean');
				expect(HolidayHelpers.getHolidayInfo(date)).toBeNull();
				expect(HolidayHelpers.getHolidayEffectMultiplier(date)).toBe(1.0);
				expect(HolidayHelpers.isWithinHolidayWindow(date).isWithinWindow).toBe(false);
				expect(HolidayHelpers.getHolidayEffect(date)).toBe(1.0);
			});

			// Test edge case years
			const edgeYears = [1970, 2000, 2100];
			edgeYears.forEach((year) => {
				const result = HolidayHelpers.getHolidaysForYear(year);
				expect(Array.isArray(result)).toBe(true);
			});
		});
