import {
	TrendingScoreCalculator,
	TrendingScoreData,
} from '@utils/trending-score-calculator.util';

describe('TrendingScoreCalculator', () => {
	describe('calculateTrendingScore', () => {
		it('should return zero score for empty data', () => {
			const data: TrendingScoreData = {
				historicalOrders: [],
				forecastedOrders: [],
				trendComponent: [],
			};

			const result = TrendingScoreCalculator.calculateTrendingScore(data);

			expect(result.trendScore).toBe(0);
			expect(result.isSignificant).toBe(false);
			expect(result.pValue).toBe(1.0);
		});

		it('should return zero score for single data points', () => {
			const data: TrendingScoreData = {
				historicalOrders: [10],
				forecastedOrders: [15],
				trendComponent: [1],
			};

			const result = TrendingScoreCalculator.calculateTrendingScore(data);

			expect(result.trendScore).toBe(0);
