import { isDevEnv, isProdEnv, isStagingEnv, isTestEnv } from '@utils/common.util';
import { getEnv } from '@utils/get-env-variable.util';

import { Environment } from '@interfaces/env-variables.interface';

const originalEnv = process.env;

jest.mock('@utils/get-env-variable.util', () => ({
	getEnv: jest.fn(),
}));

describe('common.util', () => {
	beforeAll(() => {
		process.env = { ...originalEnv };
	});
	afterEach(() => {
		jest.clearAllMocks();
	});
	afterAll(() => {
		process.env = originalEnv;
	});

	describe('isDevEnv', () => {
		beforeAll(() => {
			process.env = { ...originalEnv, NODE_ENV: 'development' };
		});
		it('should return true when NODE_ENV is DEVELOPMENT', () => {
			(getEnv as jest.Mock).mockReturnValue(Environment.DEVELOPMENT);

			const isDevEnvValue = isDevEnv();

			expect(isDevEnvValue).toBe(true);
		});

		it('should return false when NODE_ENV is not DEVELOPMENT', () => {
			(getEnv as jest.Mock).mockReturnValue(Environment.PRODUCTION);
			expect(isDevEnv()).toBe(false);
		});

		it('should return true if error occurs', () => {
			(getEnv as jest.Mock).mockImplementationOnce(() => {
				throw new Error('Simulated error');
			});

			const isDevEnvValue = isDevEnv();

			expect(isDevEnvValue).toBe(true);
		});
	});

	describe('isProdEnv', () => {
		beforeAll(() => {
			process.env = { ...originalEnv, NODE_ENV: 'production' };
		});
		it('should return true when NODE_ENV is PRODUCTION', () => {
			(getEnv as jest.Mock).mockReturnValue(Environment.PRODUCTION);
			expect(isProdEnv()).toBe(true);
		});

		it('should return false when NODE_ENV is not PRODUCTION', () => {
			(getEnv as jest.Mock).mockReturnValue(Environment.DEVELOPMENT);
			expect(isProdEnv()).toBe(false);
		});

		it('should return true if error occurs', () => {
			(getEnv as jest.Mock).mockImplementationOnce(() => {
				throw new Error('Simulated error');
			});

			const isProdEnvValue = isProdEnv();

			expect(isProdEnvValue).toBe(true);
		});
	});

	describe('isTestEnv', () => {
		beforeAll(() => {
			process.env = { ...originalEnv, NODE_ENV: 'test' };
		});
		it('should return true when NODE_ENV is TEST', () => {
			(getEnv as jest.Mock).mockReturnValue(Environment.TEST);
			expect(isTestEnv()).toBe(true);
		});

		it('should return false when NODE_ENV is not TEST', () => {
			(getEnv as jest.Mock).mockReturnValue(Environment.STAGING);
			expect(isTestEnv()).toBe(false);
		});

		it('should return true if error occurs', () => {
			(getEnv as jest.Mock).mockImplementationOnce(() => {
				throw new Error('Simulated error');
			});

			const isTestEnvValue = isTestEnv();

			expect(isTestEnvValue).toBe(true);
		});
	});

	describe('isStagingEnv', () => {
		beforeAll(() => {
			process.env = { ...originalEnv, NODE_ENV: 'staging' };
		});
		it('should return true when NODE_ENV is STAGING', () => {
			(getEnv as jest.Mock).mockReturnValue(Environment.STAGING);
			expect(isStagingEnv()).toBe(true);
		});

		it('should return false when NODE_ENV is not STAGING', () => {
			(getEnv as jest.Mock).mockReturnValue(Environment.TEST);
			expect(isStagingEnv()).toBe(false);
		});

		it('should return true if error occurs', () => {
			(getEnv as jest.Mock).mockImplementationOnce(() => {
				throw new Error('Simulated error');
			});

			const isStagingEnvValue = isStagingEnv();

			expect(isStagingEnvValue).toBe(true);
		});
	});
});

