import { LogExecution } from '@decorators/log-execution.decorator';
import * as Rollbar from 'rollbar';

jest.mock('rollbar');
jest.mock('@config/rollbar.config', () => ({
	rollbar: null,
}));

const originalProcessEnv = process.env;

describe('LogExecution Decorator', () => {
	let mockRollbar: jest.Mocked<Rollbar>;
	let consoleLogSpy: jest.SpyInstance;
	let consoleWarnSpy: jest.SpyInstance;
	let consoleErrorSpy: jest.SpyInstance;

	beforeEach(() => {
		jest.clearAllMocks();
		process.env = { ...originalProcessEnv, EXECUTION_TIME_THRESHOLD_MS: '1000' };

		mockRollbar = {
			warning: jest.fn(),
			error: jest.fn(),
			debug: jest.fn(),
		} as unknown as jest.Mocked<Rollbar>;

		consoleLogSpy = jest.spyOn(console, 'log').mockImplementation();
		consoleWarnSpy = jest.spyOn(console, 'warn').mockImplementation();
		consoleErrorSpy = jest.spyOn(console, 'error').mockImplementation();
	});

	afterEach(() => {
		consoleLogSpy.mockRestore();
		consoleWarnSpy.mockRestore();
		consoleErrorSpy.mockRestore();
		jest.restoreAllMocks();
	});

	afterAll(() => {
		process.env = originalProcessEnv;
	});

	describe('Basic Functionality', () => {
		it('should log method invocation with parameters', async () => {
			class TestClass {
				@LogExecution()
				async testMethod(param1: string, param2: number): Promise<string> {
					return `${param1}-${param2}`;
				}
			}

			const instance = new TestClass();
			const result = await instance.testMethod('test', 123);

			expect(result).toBe('test-123');
		});

		it('should log execution time', async () => {
			class TestClass {
				@LogExecution({ logExecutionTime: true })
				async testMethod(): Promise<string> {
					return 'result';
				}
			}

			const instance = new TestClass();
			await instance.testMethod();
		});

		it('should work with synchronous methods', () => {
			class TestClass {
				@LogExecution()
				syncMethod(value: number): number {
					return value * 2;
				}
			}

			const instance = new TestClass();
			const result = instance.syncMethod(5);

			expect(result).toBe(10);
		});
	});

	describe('Options Configuration', () => {
		it('should respect logParams: false option', async () => {
			class TestClass {
				@LogExecution({ logParams: false })
				async testMethod(param: string): Promise<string> {
					return param;
				}
			}

			const instance = new TestClass();
			await instance.testMethod('test-value');
		});

		it('should respect logResponse: false option', async () => {
			class TestClass {
				@LogExecution({ logResponse: false })
				async testMethod(): Promise<string> {
					return 'response-value';
				}
			}

			const instance = new TestClass();
			await instance.testMethod();
		});

		it('should respect logExecutionTime: false option', async () => {
			class TestClass {
				@LogExecution({ logExecutionTime: false })
				async testMethod(): Promise<string> {
					return 'result';
				}
			}

			const instance = new TestClass();
			await instance.testMethod();
		});

		it('should respect logErrToRollbar: false option', async () => {
			class TestClass {
				@LogExecution({ logErrToRollbar: false })
				async failingMethod(): Promise<void> {
					throw new Error('Test error');
				}
			}

			const instance = new TestClass();
			await expect(instance.failingMethod()).rejects.toThrow('Test error');
		});

		it('should use custom context in logs', async () => {
			class TestClass {
				@LogExecution({ customContext: { userId: '123', operation: 'test' } })
				async testMethod(): Promise<string> {
					return 'result';
				}
			}

			const instance = new TestClass();
			await instance.testMethod();
		});
	});

	describe('Sensitive Data Masking', () => {
		it('should mask password in parameters', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async login(username: string, password: string): Promise<string> {
					return 'logged-in';
				}
			}

			const instance = new TestClass();
			await instance.login('user', 'secret123');
		});

		it('should mask token in nested objects', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async authenticate(data: { token: string; user: string }): Promise<string> {
					return 'authenticated';
				}
			}

			const instance = new TestClass();
			await instance.authenticate({ token: 'secret-token', user: 'john' });
		});

		it('should mask authorization headers', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async makeRequest(headers: {
					authorization: string;
					contentType: string;
				}): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.makeRequest({
				authorization: 'Bearer secret',
				contentType: 'application/json',
			});
		});

		it('should mask custom sensitive keys', async () => {
			class TestClass {
				@LogExecution({
					maskSensitiveData: true,
					sensitiveKeys: ['customSecret', 'privateKey'],
				})
				async processData(data: {
					customSecret: string;
					publicData: string;
				}): Promise<string> {
					return 'processed';
				}
			}

			const instance = new TestClass();
			await instance.processData({ customSecret: 'secret', publicData: 'public' });
		});

		it('should mask sensitive data in arrays', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async processList(
					items: Array<{ name: string; password: string }>,
				): Promise<string> {
					return 'processed';
				}
			}

			const instance = new TestClass();
			await instance.processList([
				{ name: 'user1', password: 'pass1' },
				{ name: 'user2', password: 'pass2' },
			]);
		});

		it('should handle maskSensitiveData: false', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: false })
				async testMethod(password: string): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.testMethod('secret123');
		});

		it('should mask all default sensitive keys', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async testAllKeys(data: {
					password: string;
					pass: string;
					token: string;
					secret: string;
					auth: string;
					authorization: string;
					cookie: string;
					session: string;
					credentials: string;
					apiKey: string;
					_cookie: string;
					csrf: string;
					_csrf: string;
				}): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.testAllKeys({
				password: 'p',
				pass: 'p',
				token: 't',
				secret: 's',
				auth: 'a',
				authorization: 'a',
				cookie: 'c',
				session: 's',
				credentials: 'c',
				apiKey: 'a',
				_cookie: 'c',
				csrf: 'c',
				_csrf: 'c',
			});
		});
	});

	describe('Custom Formatters', () => {
		it('should use custom paramFormatter', async () => {
			class TestClass {
				@LogExecution({
					paramFormatter: (params: unknown[]) => ({
						count: (params as unknown[]).length,
					}),
				})
				async testMethod(a: string, b: number): Promise<string> {
					return 'result';
				}
			}

			const instance = new TestClass();
			await instance.testMethod('test', 123);
		});

		it('should use custom responseFormatter', async () => {
			class TestClass {
				@LogExecution({
					responseFormatter: (response: string) => ({
						length: response.length,
					}),
				})
				async testMethod(): Promise<string> {
					return 'response';
				}
			}

			const instance = new TestClass();
			await instance.testMethod();
		});
	});

	describe('Error Handling', () => {
		it('should catch and log errors', async () => {
			class TestClass {
				@LogExecution()
				async failingMethod(): Promise<void> {
					throw new Error('Test error');
				}
			}

			const instance = new TestClass();
			await expect(instance.failingMethod()).rejects.toThrow('Test error');
		});

		it('should log error with context', async () => {
			class TestClass {
				@LogExecution({ customContext: { requestId: '456' } })
				async failingMethod(): Promise<void> {
					throw new Error('Custom error');
				}
			}

			const instance = new TestClass();
			await expect(instance.failingMethod()).rejects.toThrow('Custom error');
		});

		it('should log error to Rollbar when enabled and Rollbar is available', async () => {
			const rollbarModule = require('@config/rollbar.config');
			rollbarModule.rollbar = mockRollbar;

			class TestClass {
				@LogExecution({ logErrToRollbar: true })
				async failingMethod(): Promise<void> {
					throw new Error('Rollbar error');
				}
			}

			const instance = new TestClass();
			await expect(instance.failingMethod()).rejects.toThrow('Rollbar error');

			rollbarModule.rollbar = null;
		});

		it('should handle Rollbar error logging failure gracefully', async () => {
			const rollbarModule = require('@config/rollbar.config');
			rollbarModule.rollbar = {
				error: jest.fn(() => {
					throw new Error('Rollbar failed');
				}),
			};

			class TestClass {
				@LogExecution({ logErrToRollbar: true })
				async failingMethod(): Promise<void> {
					throw new Error('Original error');
				}
			}

			const instance = new TestClass();
			await expect(instance.failingMethod()).rejects.toThrow('Original error');

			rollbarModule.rollbar = null;
		});
	});

	describe('Performance Monitoring', () => {
		it('should warn when execution time exceeds threshold', async () => {
			process.env.EXECUTION_TIME_THRESHOLD_MS = '10';

			class TestClass {
				@LogExecution()
				async slowMethod(): Promise<string> {
					await new Promise((resolve) => setTimeout(resolve, 20));
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.slowMethod();
		});

		it('should log long execution to Rollbar when enabled and Rollbar is available', async () => {
			process.env.EXECUTION_TIME_THRESHOLD_MS = '10';
			const rollbarModule = require('@config/rollbar.config');
			rollbarModule.rollbar = mockRollbar;

			class TestClass {
				@LogExecution({ logErrToRollbar: true })
				async slowMethod(): Promise<string> {
					await new Promise((resolve) => setTimeout(resolve, 20));
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.slowMethod();

			rollbarModule.rollbar = null;
		});

		it('should handle Rollbar warning logging failure gracefully', async () => {
			process.env.EXECUTION_TIME_THRESHOLD_MS = '10';
			const rollbarModule = require('@config/rollbar.config');
			rollbarModule.rollbar = {
				warning: jest.fn(() => {
					throw new Error('Rollbar warning failed');
				}),
			};

			class TestClass {
				@LogExecution({ logErrToRollbar: true })
				async slowMethod(): Promise<string> {
					await new Promise((resolve) => setTimeout(resolve, 20));
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.slowMethod();

			rollbarModule.rollbar = null;
		});

		it('should not warn when execution is below threshold', async () => {
			process.env.EXECUTION_TIME_THRESHOLD_MS = '1000';

			class TestClass {
				@LogExecution()
				async fastMethod(): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.fastMethod();
		});
	});

	describe('getRollbarInstance Edge Cases', () => {
		it('should handle Rollbar being null', async () => {
			const rollbarModule = require('@config/rollbar.config');
			rollbarModule.rollbar = null;

			class TestClass {
				@LogExecution({ logErrToRollbar: true })
				async testMethod(): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.testMethod();
		});

		it('should handle Rollbar being undefined', async () => {
			const rollbarModule = require('@config/rollbar.config');
			rollbarModule.rollbar = undefined;

			class TestClass {
				@LogExecution({ logErrToRollbar: true })
				async testMethod(): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.testMethod();
		});
	});

	describe('maskSensitiveData Function Edge Cases', () => {
		it('should handle non-object data', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async testPrimitive(value: string): Promise<string> {
					return value;
				}
			}

			const instance = new TestClass();
			await instance.testPrimitive('simple-string');
		});

		it('should handle null data', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async testNull(value: null): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.testNull(null);
		});

		it('should handle undefined data', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async testUndefined(value: undefined): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.testUndefined(undefined);
		});

		it('should handle deeply nested objects', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async testNested(data: {
					level1: { level2: { level3: { password: string } } };
				}): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.testNested({
				level1: { level2: { level3: { password: 'secret' } } },
			});
		});

		it('should handle objects with null properties', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async testNullProp(data: { key: null; password: string }): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.testNullProp({ key: null, password: 'secret' });
		});

		it('should handle empty arrays', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async testEmptyArray(items: unknown[]): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.testEmptyArray([]);
		});

		it('should handle arrays with primitives', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async testPrimitiveArray(items: number[]): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.testPrimitiveArray([1, 2, 3]);
		});

		it('should handle circular references safely', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async testCircular(data: unknown): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			const circular: Record<string, unknown> = { name: 'test' };
			circular.self = circular;

			await instance.testCircular(circular);
		});
	});

	describe('Default Options Behavior', () => {
		it('should use default options when none provided', async () => {
			class TestClass {
				@LogExecution()
				async testMethod(param: string): Promise<string> {
					return param.toUpperCase();
				}
			}

			const instance = new TestClass();
			const result = await instance.testMethod('hello');

			expect(result).toBe('HELLO');
		});

		it('should merge provided options with defaults', async () => {
			class TestClass {
				@LogExecution({ logParams: false })
				async testMethod(): Promise<string> {
					return 'result';
				}
			}

			const instance = new TestClass();
			await instance.testMethod();
		});
	});

	describe('Rollbar Level Option', () => {
		it('should support different rollbar levels', async () => {
			class TestClass {
				@LogExecution({ rollbarLevel: 'debug' })
				async debugMethod(): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.debugMethod();
		});

		it('should support info level', async () => {
			class TestClass {
				@LogExecution({ rollbarLevel: 'info' })
				async infoMethod(): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.infoMethod();
		});

		it('should support warning level', async () => {
			class TestClass {
				@LogExecution({ rollbarLevel: 'warning' })
				async warningMethod(): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.warningMethod();
		});

		it('should support error level', async () => {
			class TestClass {
				@LogExecution({ rollbarLevel: 'error' })
				async errorMethod(): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.errorMethod();
		});
	});

	describe('Complex Scenarios', () => {
		it('should handle methods returning complex objects', async () => {
			class TestClass {
				@LogExecution()
				async complexReturn(): Promise<{
					data: string[];
					metadata: { count: number };
				}> {
					return {
						data: ['a', 'b', 'c'],
						metadata: { count: 3 },
					};
				}
			}

			const instance = new TestClass();
			const result = await instance.complexReturn();

			expect(result.data).toEqual(['a', 'b', 'c']);
			expect(result.metadata.count).toBe(3);
		});

		it('should handle methods with multiple parameters of different types', async () => {
			class TestClass {
				@LogExecution()
				async multiParam(
					str: string,
					num: number,
					bool: boolean,
					obj: { key: string },
					arr: number[],
				): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.multiParam('test', 123, true, { key: 'value' }, [1, 2, 3]);
		});

		it('should handle all options together', async () => {
			class TestClass {
				@LogExecution({
					logParams: true,
					logResponse: true,
					logExecutionTime: true,
					logErrToRollbar: true,
					rollbarLevel: 'debug',
					maskSensitiveData: true,
					sensitiveKeys: ['custom'],
					customContext: { feature: 'test' },
					paramFormatter: (p: unknown) => ({ length: (p as unknown[]).length }),
					responseFormatter: (r: string) => ({ uppercase: r.toUpperCase() }),
				})
				async fullOptions(password: string, custom: string): Promise<string> {
					return 'result';
				}
			}

			const instance = new TestClass();
			await instance.fullOptions('secret', 'custom-secret');
		});
	});
});

