import { LogExecution } from '@decorators/log-execution.decorator';
import * as Rollbar from 'rollbar';

jest.mock('rollbar');
jest.mock('@config/rollbar.config', () => ({
	rollbar: null,
}));

const originalProcessEnv = process.env;

describe('LogExecution Decorator', () => {
	let mockRollbar: jest.Mocked<Rollbar>;
	let consoleLogSpy: jest.SpyInstance;
	let consoleWarnSpy: jest.SpyInstance;
	let consoleErrorSpy: jest.SpyInstance;

	beforeEach(() => {
		jest.clearAllMocks();
		process.env = { ...originalProcessEnv, EXECUTION_TIME_THRESHOLD_MS: '1000' };

		mockRollbar = {
			warning: jest.fn(),
			error: jest.fn(),
			debug: jest.fn(),
		} as unknown as jest.Mocked<Rollbar>;

		consoleLogSpy = jest.spyOn(console, 'log').mockImplementation();
		consoleWarnSpy = jest.spyOn(console, 'warn').mockImplementation();
		consoleErrorSpy = jest.spyOn(console, 'error').mockImplementation();
	});

	afterEach(() => {
		consoleLogSpy.mockRestore();
		consoleWarnSpy.mockRestore();
		consoleErrorSpy.mockRestore();
		jest.restoreAllMocks();
	});

	afterAll(() => {
		process.env = originalProcessEnv;
	});

	describe('Basic Functionality', () => {
		it('should log method invocation with parameters', async () => {
			class TestClass {
				@LogExecution()
				async testMethod(param1: string, param2: number): Promise<string> {
					return `${param1}-${param2}`;
				}
			}

			const instance = new TestClass();
			const result = await instance.testMethod('test', 123);

			expect(result).toBe('test-123');
		});

		it('should log execution time', async () => {
			class TestClass {
				@LogExecution({ logExecutionTime: true })
				async testMethod(): Promise<string> {
					return 'result';
				}
			}

			const instance = new TestClass();
			await instance.testMethod();
		});

		it('should work with synchronous methods', () => {
			class TestClass {
				@LogExecution()
				syncMethod(value: number): number {
					return value * 2;
				}
			}

			const instance = new TestClass();
			const result = instance.syncMethod(5);

			expect(result).toBe(10);
		});
	});

	describe('Options Configuration', () => {
		it('should respect logParams: false option', async () => {
			class TestClass {
				@LogExecution({ logParams: false })
				async testMethod(param: string): Promise<string> {
					return param;
				}
			}

			const instance = new TestClass();
			await instance.testMethod('test-value');
		});

		it('should respect logResponse: false option', async () => {
			class TestClass {
				@LogExecution({ logResponse: false })
				async testMethod(): Promise<string> {
					return 'response-value';
				}
			}

			const instance = new TestClass();
			await instance.testMethod();
		});

		it('should respect logExecutionTime: false option', async () => {
			class TestClass {
				@LogExecution({ logExecutionTime: false })
				async testMethod(): Promise<string> {
					return 'result';
				}
			}

			const instance = new TestClass();
			await instance.testMethod();
		});

		it('should respect logErrToRollbar: false option', async () => {
			class TestClass {
				@LogExecution({ logErrToRollbar: false })
				async failingMethod(): Promise<void> {
					throw new Error('Test error');
				}
			}

			const instance = new TestClass();
			await expect(instance.failingMethod()).rejects.toThrow('Test error');
		});

		it('should use custom context in logs', async () => {
			class TestClass {
				@LogExecution({ customContext: { userId: '123', operation: 'test' } })
				async testMethod(): Promise<string> {
					return 'result';
				}
			}

			const instance = new TestClass();
			await instance.testMethod();
		});
	});

	describe('Sensitive Data Masking', () => {
		it('should mask password in parameters', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async login(_username: string, _password: string): Promise<string> {
					return 'logged-in';
				}
			}

			const instance = new TestClass();
			await instance.login('user', 'secret123');
		});

		it('should mask token in nested objects', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async authenticate(_data: { token: string; user: string }): Promise<string> {
					return 'authenticated';
				}
			}

			const instance = new TestClass();
			await instance.authenticate({ token: 'secret-token', user: 'john' });
		});

		it('should mask authorization headers', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async makeRequest(_headers: {
					authorization: string;
					contentType: string;
				}): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.makeRequest({
				authorization: 'Bearer secret',
				contentType: 'application/json',
			});
		});

		it('should mask custom sensitive keys', async () => {
			class TestClass {
				@LogExecution({
					maskSensitiveData: true,
					sensitiveKeys: ['customSecret', 'privateKey'],
				})
				async processData(_data: {
					customSecret: string;
					publicData: string;
				}): Promise<string> {
					return 'processed';
				}
			}

			const instance = new TestClass();
			await instance.processData({ customSecret: 'secret', publicData: 'public' });
		});

		it('should mask sensitive data in arrays', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: true })
				async processList(
					_items: Array<{ name: string; password: string }>,
				): Promise<string> {
					return 'processed';
				}
			}

			const instance = new TestClass();
			await instance.processList([
				{ name: 'user1', password: 'pass1' },
				{ name: 'user2', password: 'pass2' },
			]);
		});

		it('should handle maskSensitiveData: false', async () => {
			class TestClass {
				@LogExecution({ maskSensitiveData: false })
				async testMethod(_password: string): Promise<string> {
					return 'done';
				}
			}

			const instance = new TestClass();
			await instance.testMethod('secret123');
		});

		it('should mask all default sensitive keys', async () => {
