it('should handle split()[0] returning undefined edge case in date formatting', () => {
	const testDate = createLocalDate(2024, 12, 25);
	const originalToISOString = Date.prototype.toISOString;
	const originalSplit = String.prototype.split;

	Date.prototype.toISOString = function (): string {
		return '2024-12-25T00:00:00.000Z';
	};

	String.prototype.split = function (separator?: string | RegExp, limit?: number): string[] {
		if (separator === 'T') {
			return [] as string[];
		}
		return originalSplit.call(this, separator, limit);
	};

	const result = HolidayHelpers.getHolidayInfo(testDate);
	expect(result).toBeTruthy();
	expect(result?.date).toBe('');

	Date.prototype.toISOString = originalToISOString;
	String.prototype.split = originalSplit;
});

