import { MathematicalFunctions } from '@utils/mathematical-functions.util';

describe('MathematicalFunctions', () => {
	describe('roundToPrecision', () => {
		it('should round to 2 decimal places', () => {
			const result = MathematicalFunctions.roundToPrecision({
				value: 3.14159,
				precision: 2,
			});
			expect(result).toBe(3.14);
		});

		it('should round to 0 decimal places', () => {
			const result = MathematicalFunctions.roundToPrecision({
				value: 2.718,
				precision: 0,
			});
			expect(result).toBe(3);
		});

		it('should return the value unchanged when precision is null', () => {
			const result = MathematicalFunctions.roundToPrecision({
				value: 1.23456,
				precision: null,
			});
			expect(result).toBe(1.23456);
		});

		it('should handle negative values correctly', () => {
			const result = MathematicalFunctions.roundToPrecision({
				value: -1.9876,
				precision: 2,
			});
			expect(result).toBe(-1.99);
		});

		it('should throw error if value is not a number', () => {
			expect(() =>
				// @ts-expect-error - testing invalid input
				MathematicalFunctions.roundToPrecision({ value: 'abc', precision: 2 }),
			).toThrow('Input must be a number');
		});

		it('should throw error if precision is not a number or null', () => {
			expect(() =>
				// @ts-expect-error - testing invalid input
				MathematicalFunctions.roundToPrecision({ value: 1.23, precision: '2' }),
			).toThrow('Precision must be a number or null');
		});

