   199→   199→
   200→   200→			const secondTerm =
   201→   201→				(-(alphaParameter + iteration) * (sumAlphaBeta + iteration) * inputX) /
   202→   202→				((alphaParameter + doubleIteration) * (alphaPlusOne + doubleIteration));
   203→   203→			denominatorD = 1 + secondTerm * denominatorD;
   204→   204→			if (Math.abs(denominatorD) < epsilon) {
   205→   205→				denominatorD = epsilon;
   206→   206→			}
