   231→   231→		const adjustedValue = inputValue;
   232→   232→		let yVariable = adjustedValue;
   233→   233→		let tempValue = adjustedValue + 5.5;
   234→   234→		tempValue -= (adjustedValue + 0.5) * Math.log(tempValue);
   235→   235→
   236→   236→		for (; index < coefficients.length; index++) {
   237→   237→			yVariable += 1;
   238→   238→			const coefficient = coefficients[index] as unknown as number;
   239→   239→			seriesSum += coefficient / yVariable;
   240→   240→		}
   241→   241→
   242→   242→		return -tempValue + Math.log((2.5066282746310005 * seriesSum) / adjustedValue);
   243→   243→	}
