   245→   245→	private static calculateEffectSize(
   246→   246→		group1: { mean: number; variance: number; n: number },
   247→   247→		group2: { mean: number; variance: number; n: number },
   248→   248→	): number {
   249→   249→		if (group1.n <= 1 || group2.n <= 1) return 0;
   250→   250→
   251→   251→		const pooledVariance =
   252→   252→			((group1.n - 1) * group1.variance + (group2.n - 1) * group2.variance) /
   253→   253→			(group1.n + group2.n - 2);
   254→   254→
   255→   255→		const pooledStdDev = Math.sqrt(Math.max(0, pooledVariance));
   256→   256→
   257→   257→		if (pooledStdDev === 0) return 0;
   258→   258→
   259→   259→		return (group2.mean - group1.mean) / pooledStdDev;
   260→   260→	}
