   262→   262→	private static calculateMomentum(trendComponent: number[]): number {
   263→   263→		if (trendComponent.length < 14) return 0;
   264→   264→
   265→   265→		const recentPeriod = Math.min(7, Math.floor(trendComponent.length / 2));
   266→   266→		const mediumPeriod = Math.min(14, trendComponent.length);
   267→   267→
   268→   268→		const recentTrend = trendComponent.slice(-recentPeriod);
   269→   269→		const mediumTrend = trendComponent.slice(-mediumPeriod, -recentPeriod);
   270→   270→
   271→   271→		const recentSlope = this.calculateSlope(recentTrend);
   272→   272→		const mediumSlope = this.calculateSlope(mediumTrend);
   273→   273→
   274→   274→		return recentSlope - mediumSlope;
   275→   275→	}
