   277→   277→	private static calculateSlope(dataValues: number[]): number {
   278→   278→		const dataLength = dataValues.length;
   279→   279→		if (dataLength < 2) return 0;
   280→   280→
   281→   281→		const xCoordinates = Array.from({ length: dataLength }, (_, index) => index);
   282→   282→		const xMean = (dataLength - 1) / 2;
   283→   283→		const yMean = dataValues.reduce((sum, value) => sum + value, 0) / dataLength;
   284→   284→
   285→   285→		let slopeNumerator = 0;
   286→   286→		let slopeDenominator = 0;
   287→   287→
   288→   288→		for (let index = 0; index < dataLength; index++) {
   289→   289→			const xCoordinate = xCoordinates[index] as unknown as number;
   290→   290→			const yCoordinate = dataValues[index] as unknown as number;
   291→   291→			const xDeviation = xCoordinate - xMean;
   292→   292→			const yDeviation = yCoordinate - yMean;
   293→   293→			slopeNumerator += xDeviation * yDeviation;
   294→   294→			slopeDenominator += xDeviation * xDeviation;
   295→   295→		}
   296→   296→
   297→   297→		return slopeDenominator === 0 ? 0 : slopeNumerator / slopeDenominator;
   298→   298→	}
