   300→   300→	private static calculateVolatility(dataValues: number[]): number {
   301→   301→		if (dataValues.length === 0) return 0;
   302→   302→
   303→   303→		const meanValue =
   304→   304→			dataValues.reduce((sum, value) => sum + value, 0) / dataValues.length;
   305→   305→		if (meanValue === 0) return 0;
   306→   306→
   307→   307→		const varianceValue =
   308→   308→			dataValues.reduce((sum, value) => sum + Math.pow(value - meanValue, 2), 0) /
   309→   309→			dataValues.length;
   310→   310→		const standardDeviation = Math.sqrt(varianceValue);
   311→   311→
   312→   312→		return standardDeviation / meanValue;
   313→   313→	}
