   320→   320→		const normalizedVolatility =
   321→   321→			Math.min(volatilityValue, maximumVolatility) / maximumVolatility;
   322→   322→		const volatilityPenalty = normalizedVolatility * 0.3;
   323→   323→
   324→   324→		return trendScore * (1 - volatilityPenalty);
   325→   325→	}
